import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TarotCardData {
  id: string;
  name_vi: string; // Vietnamese name
  name_en: string; // English name (for image seeding)
  type: 'major' | 'minor';
  suit?: 'wands' | 'cups' | 'swords' | 'pentacles';
  number?: number;
  meaningKeywords: string[];
}

export enum SpreadType {
  ONE_CARD = 'ONE_CARD',
  THREE_CARD = 'THREE_CARD',
  FIVE_CARD = 'FIVE_CARD',
}

export interface ReadingRequest {
  spread: SpreadType;
  question: string;
}

export interface DrawnCard {
  card: TarotCardData;
  position: number;
  positionName: string; // e.g., "Present", "Future"
  isReversed: boolean;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { DrawnCard } from '../types';

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.error("API_KEY is missing from environment variables.");
      // In a real app, we might throw an error or handle this gracefully in UI
      // For this demo, we assume key is present as per instructions.
    }
    aiClient = new GoogleGenAI({ apiKey: apiKey });
  }
  return aiClient;
};

export const interpretReading = async (
  question: string,
  drawnCards: DrawnCard[]
): Promise<ReadableStream<string>> => {
  const client = getClient();
  const modelId = "gemini-2.5-flash-latest"; // Using a fast model for text generation

  const cardsDescription = drawnCards.map((c, index) => 
    `${index + 1}. Vị trí: ${c.positionName} - Lá bài: ${c.card.name_vi} (${c.card.name_en}) - ${c.isReversed ? 'Ngược' : 'Xuôi'}`
  ).join('\n');

  const prompt = `
    Bạn là một Tarot Reader chuyên nghiệp, huyền bí và sâu sắc. 
    Hãy giải bài cho người dùng dựa trên các lá bài sau:

    Câu hỏi của người dùng: "${question || "Xem tổng quan"}"

    Các lá bài đã rút:
    ${cardsDescription}

    Yêu cầu:
    1. Giải thích ý nghĩa từng lá bài gắn với vị trí của nó.
    2. Liên kết các lá bài lại để đưa ra một câu chuyện hoặc lời khuyên tổng thể.
    3. Giọng văn nhẹ nhàng, đồng cảm, huyền bí nhưng thực tế.
    4. Sử dụng định dạng Markdown để trình bày đẹp mắt (dùng bold cho tên lá bài).
    5. Trả lời bằng Tiếng Việt.
  `;

  try {
    const responseStream = await client.models.generateContentStream({
      model: modelId,
      contents: prompt,
      config: {
        // Optional: Add safety settings or temperature if needed
        temperature: 0.7,
      }
    });

    // Convert the Gemini stream to a standard ReadableStream for the UI to consume easily
    return new ReadableStream({
      async start(controller) {
        for await (const chunk of responseStream) {
          const text = chunk.text;
          if (text) {
            controller.enqueue(text);
          }
        }
        controller.close();
      }
    });

  } catch (error) {
    console.error("Error generating tarot reading:", error);
    throw error;
  }
};

import React from 'react';
import { TarotCardData } from '../types';

interface CardProps {
  data: TarotCardData;
  isRevealed: boolean;
  isReversed: boolean;
  onClick?: () => void;
  index: number; // for animation delay
}

export const Card: React.FC<CardProps> = ({ data, isRevealed, isReversed, onClick, index }) => {
  // Use picsum with a consistent seed based on card name to simulate "card art"
  // We use grayscale and sepia filters to make random photos look more "tarot-like"
  const imageUrl = `https://picsum.photos/seed/${data.name_en.replace(/\s/g, '')}Tarot/300/500`;

  return (
    <div 
      className={`group relative w-32 h-52 md:w-48 md:h-80 cursor-pointer perspective-1000 transition-all duration-500 hover:scale-105`}
      onClick={onClick}
      style={{ transitionDelay: `${index * 100}ms` }}
    >
      <div 
        className={`relative w-full h-full duration-700 card-preserve-3d transition-transform ease-in-out ${isRevealed ? 'rotate-y-180' : ''}`}
      >
        {/* Back of Card */}
        <div className="absolute w-full h-full card-backface-hidden rounded-xl border-2 border-mystic-600 bg-mystic-800 shadow-2xl overflow-hidden">
            {/* Pattern */}
            <div className="absolute inset-0 opacity-30 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-mystic-accent via-mystic-900 to-mystic-900"></div>
            <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-20 h-20 rounded-full border-2 border-mystic-500 opacity-20 flex items-center justify-center">
                    <div className="w-16 h-16 rounded-full border border-mystic-400"></div>
                </div>
            </div>
            {/* Center Symbol */}
            <div className="absolute inset-0 flex items-center justify-center">
                 <span className="text-4xl opacity-50">🔮</span>
            </div>
        </div>

        {/* Front of Card */}
        <div 
          className={`absolute w-full h-full card-backface-hidden rotate-y-180 rounded-xl overflow-hidden shadow-[0_0_15px_rgba(251,191,36,0.3)] bg-mystic-900 border border-mystic-accent`}
        >
          {/* We apply rotation if the card is reversed */}
          <div className={`w-full h-full flex flex-col ${isReversed ? 'rotate-180' : ''}`}>
             <div className="relative flex-grow overflow-hidden bg-black">
                 <img 
                    src={imageUrl} 
                    alt={data.name_en}
                    className="w-full h-full object-cover opacity-80 filter sepia-[0.5] contrast-125 hover:scale-110 transition-transform duration-[3s]"
                 />
                 <div className="absolute inset-0 bg-gradient-to-t from-mystic-900 via-transparent to-transparent"></div>
             </div>

             <div className={`p-2 md:p-4 text-center border-t border-mystic-700 bg-mystic-900 ${isReversed ? 'rotate-180' : ''}`}>
                <h3 className="text-xs md:text-sm font-serif font-bold text-mystic-accent uppercase tracking-wider">{data.name_vi}</h3>
                <p className="text-[10px] md:text-xs text-gray-400 italic mt-1">{isReversed ? '(Ngược)' : '(Xuôi)'}</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { FULL_DECK, SPREAD_INFO } from './constants';
import { SpreadType, DrawnCard, TarotCardData } from './types';
import { Card } from './components/Card';
import { interpretReading } from './services/geminiService';
import ReactMarkdown from 'react-markdown';
import { Sparkles, RefreshCcw, Send, Loader2, ArrowLeft } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'shuffling' | 'reading'>('home');
  const [selectedSpread, setSelectedSpread] = useState<SpreadType>(SpreadType.ONE_CARD);
  const [question, setQuestion] = useState('');
  const [drawnCards, setDrawnCards] = useState<DrawnCard[]>([]);
  const [revealedCount, setRevealedCount] = useState(0);
  const [interpretation, setInterpretation] = useState('');
  const [isInterpreting, setIsInterpreting] = useState(false);

  const interpretationRef = useRef<HTMLDivElement>(null);

  // Shuffle and Draw Logic
  const startReading = () => {
    if (!question.trim() && selectedSpread !== SpreadType.ONE_CARD) {
        // Optional: force question for complex spreads, but let's allow empty for general
    }
    setView('shuffling');
    setDrawnCards([]);
    setRevealedCount(0);
    setInterpretation('');

    // Simulate shuffling time
    setTimeout(() => {
      drawCards();
      setView('reading');
    }, 2000);
  };

  const drawCards = () => {
    const spreadDetails = SPREAD_INFO[selectedSpread];
    const deck = [...FULL_DECK];
    const newDrawnCards: DrawnCard[] = [];

    // Fisher-Yates Shuffle
    for (let i = deck.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [deck[i], deck[j]] = [deck[j], deck[i]];
    }

    for (let i = 0; i < spreadDetails.count; i++) {
      const card = deck[i];
      // 30% chance of being reversed
      const isReversed = Math.random() < 0.3; 

      newDrawnCards.push({
        card,
        position: i,
        positionName: spreadDetails.positions[i],
        isReversed
      });
    }
    setDrawnCards(newDrawnCards);
  };

  const revealCard = (index: number) => {
    if (index === revealedCount) {
      setRevealedCount(prev => prev + 1);
    }
  };

  // Auto-generate interpretation when all cards are revealed
  useEffect(() => {
    if (drawnCards.length > 0 && revealedCount === drawnCards.length && !isInterpreting && !interpretation) {
      fetchInterpretation();
    }
  }, [revealedCount, drawnCards]);

  const fetchInterpretation = async () => {
    setIsInterpreting(true);
    try {
      const stream = await interpretReading(question, drawnCards);
      const reader = stream.getReader();

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        setInterpretation(prev => prev + value);

        // Auto-scroll to bottom of interpretation as it generates
        if (interpretationRef.current) {
            interpretationRef.current.scrollTop = interpretationRef.current.scrollHeight;
        }
      }
    } catch (error) {
      console.error("Error fetching interpretation", error);
      setInterpretation("Xin lỗi, linh hồn của những lá bài đang bị nhiễu loạn. Vui lòng thử lại sau.");
    } finally {
      setIsInterpreting(false);
    }
  };

  // --- VIEWS ---

  const renderHome = () => (
    <div className="flex flex-col items-center justify-center min-h-screen px-4 py-10 max-w-4xl mx-auto text-center space-y-12 animate-fadeIn">
      <div className="space-y-4">
        <h1 className="text-5xl md:text-7xl font-serif text-mystic-accent animate-float drop-shadow-[0_0_15px_rgba(251,191,36,0.5)]">
          Mystic Tarot
        </h1>
        <p className="text-mystic-200 text-lg md:text-xl font-light tracking-wide max-w-2xl mx-auto">
          Khám phá vận mệnh qua những lá bài. Hãy tịnh tâm, suy nghĩ về câu hỏi của bạn và để vũ trụ trả lời.
        </p>
      </div>

      {/* Spread Selection */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full">
        {Object.entries(SPREAD_INFO).map(([key, info]) => (
          <button
            key={key}
            onClick={() => setSelectedSpread(key as SpreadType)}
            className={`p-6 rounded-2xl border transition-all duration-300 flex flex-col items-center gap-3 group
              ${selectedSpread === key 
                ? 'bg-mystic-800 border-mystic-accent shadow-[0_0_20px_rgba(114,75,150,0.5)] transform scale-105' 
                : 'bg-mystic-900/50 border-mystic-700 hover:bg-mystic-800 hover:border-mystic-500'
              }`}
          >
             <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl mb-2
                ${selectedSpread === key ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}
             `}>
               {info.count}
             </div>
             <h3 className="text-xl font-serif font-bold text-gray-100">{info.name}</h3>
             <p className="text-sm text-gray-400 font-light">{info.description}</p>
          </button>
        ))}
      </div>

      {/* Question Input */}
      <div className="w-full max-w-lg space-y-6">
        <div className="relative">
            <input
              type="text"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              placeholder="Bạn muốn hỏi điều gì? (Tuỳ chọn)"
              className="w-full bg-mystic-900/80 border-b-2 border-mystic-600 px-4 py-3 text-center text-lg text-mystic-100 placeholder-mystic-600 focus:outline-none focus:border-mystic-accent transition-colors"
            />
            <Sparkles className="absolute right-2 top-3 w-5 h-5 text-mystic-500 animate-pulse" />
        </div>

        <button
          onClick={startReading}
          className="group relative px-8 py-4 bg-gradient-to-r from-mystic-600 to-mystic-800 rounded-full text-white font-bold tracking-widest uppercase overflow-hidden transition-all hover:scale-105 hover:shadow-[0_0_30px_rgba(251,191,36,0.4)]"
        >
          <span className="relative z-10 flex items-center gap-2">
            Rút Bài <Send className="w-4 h-4" />
          </span>
          <div className="absolute inset-0 bg-gradient-to-r from-mystic-accent to-purple-600 opacity-0 group-hover:opacity-20 transition-opacity duration-300"></div>
        </button>
      </div>
    </div>
  );

  const renderShuffling = () => (
    <div className="flex flex-col items-center justify-center min-h-screen">
       <div className="relative w-48 h-80">
          <div className="absolute inset-0 bg-mystic-800 rounded-xl border border-mystic-600 animate-ping opacity-20"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-32 h-52 bg-mystic-700 rounded-lg shadow-2xl animate-bounce">
                {/* Visual stack effect */}
                <div className="absolute top-0 left-0 w-full h-full bg-mystic-800 rounded-lg transform -rotate-6 z-0"></div>
                <div className="absolute top-0 left-0 w-full h-full bg-mystic-700 rounded-lg transform rotate-3 z-10 border border-mystic-500">
                    <div className="w-full h-full flex items-center justify-center">
                         <RefreshCcw className="w-10 h-10 text-mystic-accent animate-spin" />
                    </div>
                </div>
            </div>
          </div>
       </div>
       <h2 className="mt-12 text-2xl font-serif text-mystic-300 animate-pulse">Đang xào bài...</h2>
       <p className="text-sm text-mystic-500 mt-2">Hãy tập trung vào câu hỏi của bạn</p>
    </div>
  );

  const renderReading = () => (
    <div className="min-h-screen flex flex-col p-4 md:p-8 max-w-7xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <button 
            onClick={() => setView('home')} 
            className="flex items-center gap-2 text-mystic-400 hover:text-mystic-accent transition-colors"
        >
            <ArrowLeft className="w-5 h-5" /> Trở về
        </button>
        <h2 className="text-xl md:text-2xl font-serif text-white text-center">
            {question || "Thông điệp vũ trụ"}
        </h2>
        <div className="w-20"></div> {/* Spacer for center alignment */}
      </div>

      {/* Cards Display */}
      <div className="flex flex-wrap justify-center items-center gap-4 md:gap-8 mb-12 min-h-[350px]">
        {drawnCards.map((data, index) => (
          <div key={data.card.id} className="flex flex-col items-center space-y-4">
            <div className="relative">
                {/* Position Label above card */}
                <div className={`absolute -top-10 left-0 w-full text-center transition-opacity duration-500 ${index <= revealedCount ? 'opacity-100' : 'opacity-0'}`}>
                    <span className="text-xs uppercase tracking-widest text-mystic-400 font-bold bg-mystic-900/80 px-2 py-1 rounded">
                        {data.positionName}
                    </span>
                </div>

                <Card 
                    data={data.card} 
                    isReversed={data.isReversed}
                    isRevealed={index < revealedCount}
                    index={index}
                    onClick={() => revealCard(index)}
                />
            </div>

            {/* Tap to reveal instruction for next card */}
            {index === revealedCount && (
                 <div className="animate-bounce text-mystic-accent text-sm cursor-pointer mt-2" onClick={() => revealCard(index)}>
                    👆 Chạm để lật
                 </div>
            )}
          </div>
        ))}
      </div>

      {/* Interpretation Section */}
      <div className={`transition-all duration-1000 ease-in-out ${revealedCount === drawnCards.length ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}>
        <div className="bg-mystic-800/50 border border-mystic-700 rounded-2xl p-6 md:p-10 shadow-2xl backdrop-blur-sm">
            <div className="flex items-center gap-4 mb-6 border-b border-mystic-700 pb-4">
                <Sparkles className="w-6 h-6 text-mystic-accent" />
                <h3 className="text-2xl font-serif text-mystic-100">Lời Giải</h3>
                {isInterpreting && <Loader2 className="w-5 h-5 animate-spin text-mystic-500 ml-auto" />}
            </div>

            <div 
                ref={interpretationRef}
                className="prose prose-invert prose-p:text-mystic-200 prose-headings:text-mystic-100 prose-strong:text-mystic-accent max-w-none max-h-[500px] overflow-y-auto custom-scrollbar"
            >
                {interpretation ? (
                    <ReactMarkdown>{interpretation}</ReactMarkdown>
                ) : (
                    <div className="flex items-center gap-2 text-mystic-500 italic">
                        <Loader2 className="w-4 h-4 animate-spin" /> Đang kết nối với vũ trụ...
                    </div>
                )}
            </div>

            {!isInterpreting && interpretation && (
                <div className="mt-8 flex justify-center">
                    <button 
                        onClick={() => setView('home')}
                        className="px-6 py-2 border border-mystic-600 rounded-full text-mystic-300 hover:bg-mystic-700 transition-colors text-sm"
                    >
                        Xem quẻ mới
                    </button>
                </div>
            )}
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-[#1a1025] via-[#0f0a15] to-[#000000] text-gray-200 font-sans selection:bg-mystic-accent selection:text-mystic-900">
      {view === 'home' && renderHome()}
      {view === 'shuffling' && renderShuffling()}
      {view === 'reading' && renderReading()}
    </div>
  );
};

export default App;

