const getCardImageUrl = (data: TarotCardData) => {
    // Using Sacred Texts archive for standard Rider-Waite-Smith deck images
    const baseUrl = 'https://www.sacred-texts.com/tarot/pkt/img';
    let filename = '';

    if (data.type === 'major') {
        // Major Arcana: ar00 to ar21
        const num = data.number !== undefined ? data.number.toString().padStart(2, '0') : '00';
        filename = `ar${num}`;
    } else {
        // Minor Arcana: w01, c01, s01, p01 etc.
        const suitMap: Record<string, string> = { 'wands': 'w', 'cups': 'c', 'swords': 's', 'pentacles': 'p' };
        const suitCode = data.suit ? suitMap[data.suit] : 'w';
        const num = data.number !== undefined ? data.number.toString().padStart(2, '0') : '01';
        filename = `${suitCode}${num}`;
    }

    return `${baseUrl}/${filename}.jpg`;
};

