// Helper to generate Minor Arcana properly
const generateMinorArcana = (): TarotCardData[] => {
  const suits: { id: 'wands'|'cups'|'swords'|'pentacles', nameVi: string, nameEn: string }[] = [
    { id: 'wands', nameVi: 'Gậy', nameEn: 'Wands' },
    { id: 'cups', nameVi: 'Ly', nameEn: 'Cups' },
    { id: 'swords', nameVi: 'Kiếm', nameEn: 'Swords' },
    { id: 'pentacles', nameVi: 'Tiền', nameEn: 'Pentacles' }
  ];

  const cards: TarotCardData[] = [];

  suits.forEach(suit => {
    for (let i = 1; i <= 14; i++) {
      let nameEn = '';
      let nameVi = '';
      let idPrefix = '';

      // Determine standardized prefixes for reliable image matching
      switch(suit.id) {
        case 'wands': idPrefix = 'wa'; break;
        case 'cups': idPrefix = 'cu'; break;
        case 'swords': idPrefix = 'sw'; break;
        case 'pentacles': idPrefix = 'pe'; break;
      }

      const numStr = i.toString().padStart(2, '0');
      const id = `${idPrefix}${numStr}`; // e.g., wa01, sw14

      // Naming logic
      if (i === 1) { nameEn = `Ace of ${suit.nameEn}`; nameVi = `Ách ${suit.nameVi}`; }
      else if (i <= 10) { nameEn = `${i} of ${suit.nameEn}`; nameVi = `${i} ${suit.nameVi}`; }
      else if (i === 11) { nameEn = `Page of ${suit.nameEn}`; nameVi = `Tiểu Đồng ${suit.nameVi}`; }
      else if (i === 12) { nameEn = `Knight of ${suit.nameEn}`; nameVi = `Hiệp Sĩ ${suit.nameVi}`; }
      else if (i === 13) { nameEn = `Queen of ${suit.nameEn}`; nameVi = `Nữ Hoàng ${suit.nameVi}`; }
      else if (i === 14) { nameEn = `King of ${suit.nameEn}`; nameVi = `Vua ${suit.nameVi}`; }

      // Generic meanings (placeholder for full 78 deck generation)
      // In a production app, these would be fully detailed like Major Arcana
      const meaningUpright = `Đại diện cho năng lượng của bộ ${suit.nameVi} ở cấp độ ${nameVi}. Một thông điệp tích cực về sự phát triển và cơ hội trong lĩnh vực liên quan.`;
      const meaningReversed = `Năng lượng của ${suit.nameVi} bị chặn hoặc thể hiện thái quá. Cần xem xét lại cách tiếp cận vấn đề.`;

      cards.push({
        id,
        name_vi: nameVi,
        name_en: nameEn,
        type: 'minor',
        suit: suit.id,
        number: i,
        meaningKeywords: [suit.nameVi, nameVi], // Placeholder
        meaning_upright: meaningUpright,
        meaning_reversed: meaningReversed
      });
    }
  });

  return cards;
};

export const MINOR_ARCANA = generateMinorArcana();
export const FULL_DECK = [...MAJOR_ARCANA, ...MINOR_ARCANA];

