const getCardImageUrl = (data: TarotCardData) => {
    // We use a GitHub raw source which is stable and follows the standard RWS naming convention.
    // Source: https://github.com/tleniol/tarot-api/tree/master/public/images
    // Format: ar00.jpg (Major), wa01.jpg (Wands), cu01.jpg (Cups), sw01.jpg (Swords), pe01.jpg (Pentacles)

    const baseUrl = 'https://raw.githubusercontent.com/tleniol/tarot-api/master/public/images';

    // The ID logic in constants.ts is now aligned with this:
    // Major: ar00 - ar21
    // Minor: wa01 - wa14, etc.
    // We strip the ID from the data which is already formatted correctly in constants.ts
    const filename = `${data.id}.jpg`;

    return `${baseUrl}/${filename}`;
};

