              className="w-full bg-mystic-900/80 border-b-2 border-mystic-600 px-4 py-3 text-center text-lg text-mystic-100 placeholder-mystic-600 focus:outline-none focus:border-mystic-accent transition-colors"
            />
            <Sparkles className="absolute right-2 top-3 w-5 h-5 text-mystic-500 animate-pulse" />
        </div>

        <button
          onClick={startReading}
          className="group relative px-8 py-4 bg-gradient-to-r from-mystic-600 to-mystic-800 rounded-full text-white font-bold tracking-widest uppercase overflow-hidden transition-all hover:scale-105 hover:shadow-[0_0_30px_rgba(251,191,36,0.4)]"
        >
          <span className="relative z-10 flex items-center gap-2">
            Rút Bài
          </span>
          <div className="absolute inset-0 bg-gradient-to-r from-mystic-accent to-purple-600 opacity-0 group-hover:opacity-20 transition-opacity duration-300"></div>
        </button>
      </div>
    </div>
  );

  const renderShuffling = () => (
    <div className="flex flex-col items-center justify-center min-h-screen">
       <div className="relative w-48 h-80">
          <div className="absolute inset-0 bg-mystic-800 rounded-xl border-2 border-mystic-500 shadow-[0_0_30px_rgba(114,75,150,0.6)] animate-pulse"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-32 h-52 bg-mystic-700 rounded-lg shadow-2xl animate-bounce">
                <div className="absolute top-0 left-0 w-full h-full bg-mystic-800 rounded-lg transform -rotate-6 z-0 border border-mystic-600"></div>
                <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-mystic-700 to-mystic-900 rounded-lg transform rotate-3 z-10 border-2 border-mystic-accent flex flex-col items-center justify-center">
                     <RefreshCcw className="w-10 h-10 text-mystic-accent animate-spin mb-2" />
                     <span className="text-xs text-mystic-200 uppercase tracking-widest font-bold">Mystic</span>
                </div>
            </div>
          </div>
       </div>
       <h2 className="mt-12 text-2xl font-serif text-mystic-100 font-bold tracking-wide">Đang xào bài...</h2>
       <p className="text-sm text-mystic-400 mt-2">Tập trung năng lượng vào câu hỏi của bạn</p>
    </div>
  );

  const renderReading = () => (
    <div className="min-h-screen flex flex-col p-4 md:p-8 max-w-7xl mx-auto pb-24">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <button 
            onClick={() => setView('home')} 
            className="flex items-center gap-2 text-mystic-400 hover:text-mystic-accent transition-colors bg-mystic-900/50 px-3 py-1 rounded-full border border-mystic-800"
        >
            <ArrowLeft className="w-4 h-4" /> Trở về
        </button>
        <h2 className="text-lg md:text-xl font-serif text-white text-center truncate px-2">
            {question || "Thông điệp vũ trụ"}
        </h2>
        <div className="w-20"></div> 
      </div>

      {/* Cards Display */}
      <div className="flex flex-wrap justify-center items-start gap-4 md:gap-6 mb-8">
        {drawnCards.map((data, index) => (
          <div key={`${data.card.id}-${index}`} className="flex flex-col items-center space-y-2">
            <div className="relative">
                {/* Position Label */}
                <div className={`absolute -top-8 left-0 w-full text-center transition-opacity duration-300 ${index <= revealedCount ? 'opacity-100' : 'opacity-0'}`}>
                    <span className="text-[10px] uppercase tracking-widest text-mystic-300 font-bold bg-mystic-900 px-2 py-1 rounded border border-mystic-700">
                        {data.positionName}
