import { GoogleGenAI } from "@google/genai";
import { DrawnCard } from '../types';

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    // Safely attempt to access API_KEY without crashing if process is undefined
    let apiKey = '';
    try {
      if (typeof process !== 'undefined' && process.env) {
        apiKey = process.env.API_KEY || '';
      }
    } catch (e) {
      console.warn("Could not access process.env");
    }

    if (!apiKey) {
      console.warn("API_KEY is missing. AI features will not work.");
    }
    aiClient = new GoogleGenAI({ apiKey });
  }
  return aiClient;
};

export const interpretReading = async (
  question: string,
  drawnCards: DrawnCard[]
): Promise<ReadableStream<string>> => {
  const client = getClient();
  const modelId = "gemini-3-flash-preview";

  const cardsDescription = drawnCards.map((c, index) => 
    `${index + 1}. Vị trí: ${c.positionName}
     - Lá bài: ${c.card.name_vi} (${c.card.name_en}) [${c.isReversed ? 'Ngược' : 'Xuôi'}]
     - Ý nghĩa cơ bản: ${c.isReversed ? c.card.meaning_reversed : c.card.meaning_upright}`
  ).join('\n');

  const prompt = `
    Bạn là một Tarot Reader chuyên nghiệp. Người dùng vừa thực hiện một trải bài.
    Họ đã ĐÃ ĐỌC ý nghĩa cơ bản của từng lá bài. Nhiệm vụ của bạn KHÔNG PHẢI là giải thích lại từng lá bài riêng lẻ, mà là TỔNG HỢP và LIÊN KẾT chúng.

    Câu hỏi của người dùng: "${question || "Xem tổng quan vận mệnh"}"

    Các lá bài đã rút:
    ${cardsDescription}

    Yêu cầu:
    1. Tổng hợp thông điệp: Tìm mối liên hệ giữa các lá bài (ví dụ: nhiều lá Major Arcana, nhiều lá cùng chất, sự mâu thuẫn giữa các vị trí).
    2. Đưa ra một câu chuyện liền mạch hoặc lời khuyên cụ thể dựa trên sự kết hợp này.
    3. Trả lời ngắn gọn, súc tích (khoảng 150-200 từ), giọng văn huyền bí nhưng chân thành và khích lệ.
    4. KHÔNG dùng định dạng Markdown phức tạp (như đậm, nghiêng, tiêu đề). Hãy dùng văn bản thường, phân đoạn rõ ràng bằng cách xuống dòng.
    5. Ngôn ngữ: Tiếng Việt.
  `;

  try {
    const responseStream = await client.models.generateContentStream({
      model: modelId,
      contents: prompt,
      config: {
        temperature: 0.7,
      }
    });

    return new ReadableStream({
      async start(controller) {
        for await (const chunk of responseStream) {
          const text = chunk.text;
          if (text) {
            controller.enqueue(text);
          }
        }
        controller.close();
      }
    });

  } catch (error) {
    console.error("Error generating tarot reading:", error);
    return new ReadableStream({
        start(controller) {
            controller.enqueue("Không thể kết nối với Vũ trụ (Lỗi kết nối hoặc thiếu API Key). Tuy nhiên, bạn vẫn có thể tự chiêm nghiệm qua ý nghĩa các lá bài đã hiện.");
            controller.close();
        }
    });
  }
};

import React, { Component, ReactNode } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("App crashed:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: 20, color: '#fff', backgroundColor: '#1a1025', height: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
          <h1 style={{ color: '#fbbf24' }}>Đã xảy ra lỗi hệ thống</h1>
          <p>Ứng dụng đã gặp sự cố. Vui lòng tải lại trang.</p>
          <p style={{ color: '#999', fontSize: '0.8rem', marginTop: 10 }}>{this.state.error?.message}</p>
          <button 
            onClick={() => window.location.reload()}
            style={{ marginTop: 20, padding: '10px 20px', background: '#fbbf24', color: '#000', border: 'none', borderRadius: 5, cursor: 'pointer' }}
          >
            Tải lại trang
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

