    if (!apiKey) {
      console.warn("API_KEY is missing. AI features will not work.");
    }
    aiClient = new GoogleGenAI({ apiKey });
  }
  return aiClient;
};

export const interpretReading = async (
  question: string,
  drawnCards: DrawnCard[]
): Promise<ReadableStream<string>> => {
  const client = getClient();
  const modelId = "gemini-3-flash-preview";

  const cardsDescription = drawnCards.map((c, index) => 
    `${index + 1}. Vị trí: ${c.positionName}
     - Lá bài: ${c.card.name_vi} (${c.card.name_en}) [${c.isReversed ? 'Ngược' : 'Xuôi'}]
     - Ý nghĩa cơ bản: ${c.isReversed ? c.card.meaning_reversed : c.card.meaning_upright}`
  ).join('\n');

  const systemInstruction = `
    Bạn là một Tarot Reader chuyên nghiệp.
    Nhiệm vụ của bạn KHÔNG PHẢI là giải thích lại từng lá bài riêng lẻ, mà là TỔNG HỢP và LIÊN KẾT chúng để trả lời câu hỏi của người dùng.

    Phong cách:
    - Giọng văn huyền bí nhưng chân thành và khích lệ.
    - Ngắn gọn, súc tích (khoảng 150-200 từ).
    - KHÔNG dùng định dạng Markdown phức tạp (như đậm, nghiêng, tiêu đề). Dùng văn bản thường.
    - Ngôn ngữ: Tiếng Việt.
  `;

  const userPrompt = `
    Câu hỏi: "${question || "Xem tổng quan vận mệnh"}"

    Các lá bài đã rút:
    ${cardsDescription}

    Hãy tổng hợp thông điệp, tìm mối liên hệ giữa các lá bài (ví dụ: các lá cùng bộ, Major Arcana...) và đưa ra lời khuyên cụ thể.
  `;

  try {
    const responseStream = await client.models.generateContentStream({
      model: modelId,
      contents: userPrompt,
      config: {
        temperature: 0.7,
        systemInstruction: systemInstruction,
      }
    });

    return new ReadableStream({
      async start(controller) {
        for await (const chunk of responseStream) {
          const text = chunk.text;
          if (text) {
            controller.enqueue(text);
          }
        }
        controller.close();
      }
    });

  } catch (error) {
    console.error("Error generating tarot reading:", error);
    return new ReadableStream({
        start(controller) {
            controller.enqueue("Không thể kết nối với Vũ trụ (Lỗi kết nối hoặc thiếu API Key). Tuy nhiên, bạn vẫn có thể tự chiêm nghiệm qua ý nghĩa các lá bài đã hiện.");
            controller.close();
        }
    });
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { FULL_DECK, SPREAD_INFO } from './constants';
import { SpreadType, DrawnCard, TarotCardData } from './types';
import { Card } from './components/Card';
import { interpretReading } from './services/geminiService';
import { Sparkles, RefreshCcw, Loader2, ArrowLeft, BookOpen } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'shuffling' | 'reading'>('home');
  const [selectedSpread, setSelectedSpread] = useState<SpreadType>(SpreadType.ONE_CARD);
  const [question, setQuestion] = useState('');
  const [drawnCards, setDrawnCards] = useState<DrawnCard[]>([]);
  const [revealedCount, setRevealedCount] = useState(0);
  const [interpretation, setInterpretation] = useState('');
  const [isInterpreting, setIsInterpreting] = useState(false);

  // Track the most recently revealed card to show its meaning immediately
  const [activeCardIndex, setActiveCardIndex] = useState<number | null>(null);

  const interpretationRef = useRef<HTMLDivElement>(null);
  // Abort controller ref to cancel stream on unmount
  const abortControllerRef = useRef<AbortController | null>(null);

  // Shuffle and Draw Logic
  const startReading = () => {
    setView('shuffling');
    setDrawnCards([]);
    setRevealedCount(0);
    setInterpretation('');
    setActiveCardIndex(null);

    // Simulate shuffling time
    setTimeout(() => {
      drawCards();
      setView('reading');
    }, 2000);
  };

  const drawCards = () => {
    const spreadDetails = SPREAD_INFO[selectedSpread];
    const deck = [...FULL_DECK];
    const newDrawnCards: DrawnCard[] = [];

    // Fisher-Yates Shuffle
    for (let i = deck.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [deck[i], deck[j]] = [deck[j], deck[i]];
    }

    for (let i = 0; i < spreadDetails.count; i++) {
      const card = deck[i];
      // Cards are always upright as per request
      const isReversed = false; 

      newDrawnCards.push({
        card,
        position: i,
        positionName: spreadDetails.positions[i],
        isReversed
      });
    }
    setDrawnCards(newDrawnCards);
  };

  const revealCard = (index: number) => {
    // Only reveal if it's the next card in sequence or already revealed
    if (index === revealedCount) {
      setRevealedCount(prev => prev + 1);
      setActiveCardIndex(index); // Set focus to this card to show meaning
    } else if (index < revealedCount) {
      setActiveCardIndex(index); // Just change focus if already revealed
    }
  };

  // Auto-generate summary interpretation when all cards are revealed
  useEffect(() => {
    if (drawnCards.length > 0 && revealedCount === drawnCards.length && !isInterpreting && !interpretation) {
      fetchInterpretation();
    }

    // Cleanup on unmount or when dependencies change
    return () => {
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
        }
    };
  }, [revealedCount, drawnCards]);

  const fetchInterpretation = async () => {
    setIsInterpreting(true);
    abortControllerRef.current = new AbortController();

    try {
      const stream = await interpretReading(question, drawnCards);
      const reader = stream.getReader();

      while (true) {
        // Check if aborted before reading
        if (abortControllerRef.current?.signal.aborted) {
            reader.cancel();
            break;
        }

        try {
            const { done, value } = await reader.read();
            if (done) break;

            // Update state safely
            setInterpretation(prev => prev + value);

            if (interpretationRef.current) {
                interpretationRef.current.scrollTop = interpretationRef.current.scrollHeight;
            }
        } catch (readError) {
            console.warn("Stream reading interrupted", readError);
            break; 
        }
      }
    } catch (error) {
      console.error("Error fetching interpretation", error);
      setInterpretation("Xin lỗi, vũ trụ đang bận rộn. Vui lòng thử lại sau để nhận lời khuyên tổng hợp.");
    } finally {
      setIsInterpreting(false);
      abortControllerRef.current = null;
    }
  };

  // --- VIEWS ---

  const renderHome = () => (
    <div className="flex flex-col items-center justify-center min-h-screen px-4 py-10 max-w-4xl mx-auto text-center space-y-12 animate-fadeIn">
      <div className="space-y-4">
        <h1 className="text-5xl md:text-7xl font-serif text-mystic-accent animate-float drop-shadow-[0_0_15px_rgba(251,191,36,0.5)]">
          Mystic Tarot
        </h1>
        <p className="text-mystic-200 text-lg md:text-xl font-light tracking-wide max-w-2xl mx-auto">
          Khám phá vận mệnh qua những lá bài. Hình ảnh trực quan, giải nghĩa tức thì.
        </p>
      </div>

      {/* Spread Selection */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full">
        {Object.entries(SPREAD_INFO).map(([key, info]) => (
          <button
            key={key}
            onClick={() => setSelectedSpread(key as SpreadType)}
            className={`p-6 rounded-2xl border transition-all duration-300 flex flex-col items-center gap-3 group
              ${selectedSpread === key 
                ? 'bg-mystic-800 border-mystic-accent shadow-[0_0_20px_rgba(114,75,150,0.5)] transform scale-105' 
                : 'bg-mystic-900/50 border-mystic-700 hover:bg-mystic-800 hover:border-mystic-500'
              }`}
          >
             <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl mb-2
                ${selectedSpread === key ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}
             `}>
               {info.count}
             </div>
             <h3 className="text-xl font-serif font-bold text-gray-100">{info.name}</h3>
             <p className="text-sm text-gray-400 font-light">{info.description}</p>
          </button>
        ))}
      </div>

      {/* Question Input */}
      <div className="w-full max-w-lg space-y-6">
        <div className="relative">
            <input
              type="text"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              placeholder="Bạn muốn hỏi điều gì? (Tuỳ chọn)"
              className="w-full bg-mystic-900/80 border-b-2 border-mystic-600 px-4 py-3 text-center text-lg text-mystic-100 placeholder-mystic-600 focus:outline-none focus:border-mystic-accent transition-colors"
            />
            <Sparkles className="absolute right-2 top-3 w-5 h-5 text-mystic-500 animate-pulse" />
        </div>

        <button
          onClick={startReading}
          className="group relative px-8 py-4 bg-gradient-to-r from-mystic-600 to-mystic-800 rounded-full text-white font-bold tracking-widest uppercase overflow-hidden transition-all hover:scale-105 hover:shadow-[0_0_30px_rgba(251,191,36,0.4)]"
        >
          <span className="relative z-10 flex items-center gap-2">
            Rút Bài
          </span>
          <div className="absolute inset-0 bg-gradient-to-r from-mystic-accent to-purple-600 opacity-0 group-hover:opacity-20 transition-opacity duration-300"></div>
        </button>
      </div>
    </div>
  );

  const renderShuffling = () => (
    <div className="flex flex-col items-center justify-center min-h-screen">
       <div className="relative w-48 h-80">
          <div className="absolute inset-0 bg-mystic-800 rounded-xl border-2 border-mystic-500 shadow-[0_0_30px_rgba(114,75,150,0.6)] animate-pulse"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-32 h-52 bg-mystic-700 rounded-lg shadow-2xl animate-bounce">
                <div className="absolute top-0 left-0 w-full h-full bg-mystic-800 rounded-lg transform -rotate-6 z-0 border border-mystic-600"></div>
                <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-mystic-700 to-mystic-900 rounded-lg transform rotate-3 z-10 border-2 border-mystic-accent flex flex-col items-center justify-center">
                     <RefreshCcw className="w-10 h-10 text-mystic-accent animate-spin mb-2" />
                     <span className="text-xs text-mystic-200 uppercase tracking-widest font-bold">Mystic</span>
                </div>
            </div>
          </div>
       </div>
       <h2 className="mt-12 text-2xl font-serif text-mystic-100 font-bold tracking-wide">Đang xào bài...</h2>
       <p className="text-sm text-mystic-400 mt-2">Tập trung năng lượng vào câu hỏi của bạn</p>
    </div>
  );

  const renderReading = () => (
    <div className="min-h-screen flex flex-col p-4 md:p-8 max-w-7xl mx-auto pb-24">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <button 
            onClick={() => setView('home')} 
            className="flex items-center gap-2 text-mystic-400 hover:text-mystic-accent transition-colors bg-mystic-900/50 px-3 py-1 rounded-full border border-mystic-800"
        >
            <ArrowLeft className="w-4 h-4" /> Trở về
        </button>
        <h2 className="text-lg md:text-xl font-serif text-white text-center truncate px-2">
            {question || "Thông điệp vũ trụ"}
        </h2>
        <div className="w-20"></div> 
      </div>

      {/* Cards Display */}
      <div className="flex flex-wrap justify-center items-start gap-4 md:gap-6 mb-8">
        {drawnCards.map((data, index) => (
          <div key={`${data.card.id}-${index}`} className="flex flex-col items-center space-y-2">
            <div className="relative">
                {/* Position Label */}
                <div className={`absolute -top-8 left-0 w-full text-center transition-opacity duration-300 ${index <= revealedCount ? 'opacity-100' : 'opacity-0'}`}>
                    <span className="text-[10px] uppercase tracking-widest text-mystic-300 font-bold bg-mystic-900 px-2 py-1 rounded border border-mystic-700">
                        {data.positionName}
                    </span>
                </div>

                <div className={`${activeCardIndex === index ? 'ring-2 ring-mystic-accent ring-offset-2 ring-offset-mystic-900 rounded-xl' : ''} transition-all duration-300`}>
                  <Card 
                      data={data.card} 
                      isReversed={data.isReversed}
                      isRevealed={index < revealedCount}
                      index={index}
                      onClick={() => revealCard(index)}
                  />
                </div>
            </div>

            {/* Click Indicator */}
            {index === revealedCount && (
                 <div className="animate-bounce text-mystic-accent text-xs font-bold cursor-pointer bg-mystic-800/80 px-2 py-1 rounded-full" onClick={() => revealCard(index)}>
                    👆 Lật bài
                 </div>
            )}
          </div>
        ))}
      </div>

      {/* STATIC MEANING SECTION (Visible Immediately) */}
      {activeCardIndex !== null && activeCardIndex < drawnCards.length && (
         <div className="w-full max-w-2xl mx-auto mb-8 animate-fadeIn">
            <div className="bg-mystic-800 border-l-4 border-mystic-accent rounded-r-lg p-5 shadow-lg">
                <div className="flex items-start gap-3">
                    <div className="mt-1 bg-mystic-700 p-2 rounded-full">
                        <BookOpen className="w-5 h-5 text-mystic-accent" />
                    </div>
                    <div>
                        <h3 className="text-xl font-serif font-bold text-white">
                            {drawnCards[activeCardIndex].card.name_vi} 
                            <span className="text-sm font-sans font-normal text-mystic-400 ml-2">
                                ({drawnCards[activeCardIndex].card.name_en}) 
                            </span>
                        </h3>
                        <p className="text-sm text-mystic-400 mb-2 uppercase tracking-wide font-semibold">
                            {drawnCards[activeCardIndex].positionName}
                        </p>
                        <p className="text-mystic-100 text-lg leading-relaxed">
                            {drawnCards[activeCardIndex].card.meaning_upright}
                        </p>
                    </div>
                </div>
            </div>
         </div>
      )}

      {/* AI Interpretation Section (Loads at the end) */}
      <div className={`transition-all duration-1000 ease-in-out ${revealedCount === drawnCards.length ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}>
        <div className="bg-gradient-to-b from-mystic-800 to-mystic-900 border border-mystic-700 rounded-2xl p-6 md:p-8 shadow-2xl">
            <div className="flex items-center gap-4 mb-4 border-b border-mystic-700 pb-4">
                <Sparkles className="w-6 h-6 text-mystic-accent" />
                <h3 className="text-xl font-serif text-mystic-100">Tổng quan & Lời khuyên từ Vũ trụ</h3>
                {isInterpreting && <Loader2 className="w-5 h-5 animate-spin text-mystic-500 ml-auto" />}
            </div>

            <div 
                ref={interpretationRef}
                className="prose prose-invert max-w-none max-h-[400px] overflow-y-auto custom-scrollbar"
            >
                {interpretation ? (
                     <div className="whitespace-pre-wrap font-serif text-mystic-100 leading-relaxed text-base md:text-lg">
                        {interpretation}
                     </div>
                ) : (
                    <div className="flex flex-col items-center justify-center py-8 text-mystic-500 gap-3">
                        <Loader2 className="w-6 h-6 animate-spin" /> 
                        <span className="italic">Đang kết nối các lá bài để đưa ra lời khuyên tổng thể...</span>
                    </div>
                )}
            </div>

            {!isInterpreting && interpretation && (
                <div className="mt-6 flex justify-center">
                    <button 
                        onClick={() => setView('home')}
                        className="px-8 py-3 bg-mystic-700 hover:bg-mystic-600 rounded-full text-white font-bold transition-all shadow-lg border border-mystic-500"
                    >
                        Xem quẻ mới
                    </button>
                </div>
            )}
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0f0a15] text-gray-200 font-sans selection:bg-mystic-accent selection:text-mystic-900">
      {view === 'home' && renderHome()}
      {view === 'shuffling' && renderShuffling()}
      {view === 'reading' && renderReading()}
    </div>
  );
};

