                    key={idx} 
                    className={`bg-mystic-800/80 border rounded-lg p-4 transition-all duration-300 ${activeCardIndex === idx ? 'border-mystic-accent shadow-lg bg-mystic-800' : 'border-mystic-700 hover:border-mystic-500'}`}
                    onClick={() => setActiveCardIndex(idx)}
                  >
                      <div className="flex items-start gap-3">
                          <div className={`mt-1 w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${activeCardIndex === idx ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}`}>
                              {idx + 1}
                          </div>
                          <div>
                              <div className="flex flex-col sm:flex-row sm:items-center sm:gap-2 mb-1">
                                  <h4 className={`font-serif font-bold ${activeCardIndex === idx ? 'text-white' : 'text-mystic-100'}`}>
                                      {cardData.card.name_vi}
                                  </h4>
                                  <span className="text-xs text-mystic-400 font-sans">({cardData.card.name_en})</span>
                              </div>
                              <p className="text-xs text-mystic-400 uppercase tracking-wider mb-2">{cardData.positionName}</p>
                              <p className="text-mystic-200 text-sm leading-relaxed">
                                  {cardData.card.meaning_upright}
                              </p>
                          </div>
                      </div>
                  </div>
              ))}
            </div>
         </div>
      )}

      {/* AI Interpretation Section (Loads at the end) */}
      <div className={`transition-all duration-1000 ease-in-out ${revealedCount === drawnCards.length ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}>
        <div className="bg-gradient-to-b from-mystic-800 to-mystic-900 border border-mystic-700 rounded-2xl p-6 md:p-8 shadow-2xl">
            <div className="flex items-center gap-4 mb-4 border-b border-mystic-700 pb-4">
                <Sparkles className="w-6 h-6 text-mystic-accent" />
                <h3 className="text-xl font-serif text-mystic-100">Tổng quan & Lời khuyên từ Vũ trụ</h3>
                {isInterpreting && <Loader2 className="w-5 h-5 animate-spin text-mystic-500 ml-auto" />}
            </div>

            <div 
                ref={interpretationRef}
                className="prose prose-invert max-w-none max-h-[400px] overflow-y-auto custom-scrollbar"
            >
                {interpretation ? (
                     <div className="whitespace-pre-wrap font-serif text-mystic-100 leading-relaxed text-base md:text-lg">
                        {interpretation}
                     </div>
                ) : (
                    <div className="flex flex-col items-center justify-center py-8 text-mystic-500 gap-3">
                        <Loader2 className="w-6 h-6 animate-spin" /> 
                        <span className="italic">Đang kết nối các lá bài để đưa ra lời khuyên tổng thể...</span>
                    </div>
                )}
            </div>

            {!isInterpreting && interpretation && (
                <div className="mt-6 flex justify-center">
                    <button 
                        onClick={() => setView('home')}
                        className="px-8 py-3 bg-mystic-700 hover:bg-mystic-600 rounded-full text-white font-bold transition-all shadow-lg border border-mystic-500"
                    >
                        Xem quẻ mới
                    </button>
                </div>
            )}
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0f0a15] text-gray-200 font-sans selection:bg-mystic-accent selection:text-mystic-900">
      {view === 'home' && renderHome()}
      {view === 'shuffling' && renderShuffling()}
      {view === 'reading' && renderReading()}
    </div>
  );
};

