import React, { Component, ReactNode, ErrorInfo } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("App crashed:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: 20, color: '#fff', backgroundColor: '#1a1025', height: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
          <h1 style={{ color: '#fbbf24' }}>Đã xảy ra lỗi hệ thống</h1>
          <p>Ứng dụng đã gặp sự cố. Vui lòng tải lại trang.</p>
          <p style={{ color: '#999', fontSize: '0.8rem', marginTop: 10 }}>{this.state.error?.message}</p>
          <button 
            onClick={() => window.location.reload()}
            style={{ marginTop: 20, padding: '10px 20px', background: '#fbbf24', color: '#000', border: 'none', borderRadius: 5, cursor: 'pointer' }}
          >
            Tải lại trang
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  </React.StrictMode>
);

import React, { useState, useEffect, useRef } from 'react';
import { FULL_DECK, SPREAD_INFO } from './constants';
import { SpreadType, DrawnCard, TarotCardData } from './types';
import { Card } from './components/Card';
import { interpretReading } from './services/geminiService';
import { Sparkles, RefreshCcw, Loader2, ArrowLeft, BookOpen, ScrollText, Download, X, MoreVertical, Share, ArrowUpRight } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'shuffling' | 'reading'>('home');
  const [selectedSpread, setSelectedSpread] = useState<SpreadType>(SpreadType.ONE_CARD);
  const [question, setQuestion] = useState('');
  const [drawnCards, setDrawnCards] = useState<DrawnCard[]>([]);
  const [revealedCount, setRevealedCount] = useState(0);
  const [interpretation, setInterpretation] = useState('');
  const [isInterpreting, setIsInterpreting] = useState(false);

  // PWA State
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showInstallModal, setShowInstallModal] = useState(false);
  const [isIOS, setIsIOS] = useState(false);

  // Track the most recently revealed card to show its meaning immediately
  const [activeCardIndex, setActiveCardIndex] = useState<number | null>(null);

  const interpretationRef = useRef<HTMLDivElement>(null);
  // Abort controller ref to cancel stream on unmount
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Detect iOS
    const isIosDevice = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
    setIsIOS(isIosDevice);

    const handler = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
      console.log("Install prompt captured");
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (deferredPrompt) {
      // If the browser provided a prompt event, use it
      deferredPrompt.prompt();
      deferredPrompt.userChoice.then((choiceResult: any) => {
        if (choiceResult.outcome === 'accepted') {
          console.log('User accepted the install prompt');
        }
        setDeferredPrompt(null);
      });
    } else {
      // Otherwise, show manual instructions
      setShowInstallModal(true);
    }
  };

  // Shuffle and Draw Logic
  const startReading = () => {
    setView('shuffling');
    setDrawnCards([]);
    setRevealedCount(0);
    setInterpretation('');
    setActiveCardIndex(null);

    // Simulate shuffling time
    setTimeout(() => {
      drawCards();
      setView('reading');
    }, 2000);
  };

  const drawCards = () => {
    const spreadDetails = SPREAD_INFO[selectedSpread];
    const deck = [...FULL_DECK];
    const newDrawnCards: DrawnCard[] = [];

    // Fisher-Yates Shuffle
    for (let i = deck.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [deck[i], deck[j]] = [deck[j], deck[i]];
    }

    for (let i = 0; i < spreadDetails.count; i++) {
      const card = deck[i];
      // Cards are always upright as per request
      const isReversed = false; 

      newDrawnCards.push({
        card,
        position: i,
        positionName: spreadDetails.positions[i],
        isReversed
      });
    }
    setDrawnCards(newDrawnCards);
  };

  const revealCard = (index: number) => {
    // Only reveal if it's the next card in sequence or already revealed
    if (index === revealedCount) {
      setRevealedCount(prev => prev + 1);
      setActiveCardIndex(index); // Set focus to this card to show meaning
    } else if (index < revealedCount) {
      setActiveCardIndex(index); // Just change focus if already revealed
    }
  };

  // Auto-generate summary interpretation when all cards are revealed
  useEffect(() => {
    if (drawnCards.length > 0 && revealedCount === drawnCards.length && !isInterpreting && !interpretation) {
      fetchInterpretation();
    }

    // Cleanup on unmount or when dependencies change
    return () => {
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
        }
    };
  }, [revealedCount, drawnCards]);

  const fetchInterpretation = async () => {
    setIsInterpreting(true);
    abortControllerRef.current = new AbortController();

    try {
      const stream = await interpretReading(question, drawnCards);
      const reader = stream.getReader();

      while (true) {
        // Check if aborted before reading
        if (abortControllerRef.current?.signal.aborted) {
            reader.cancel();
            break;
        }

        try {
            const { done, value } = await reader.read();
            if (done) break;

            // Update state safely
            setInterpretation(prev => prev + value);

            if (interpretationRef.current) {
                interpretationRef.current.scrollTop = interpretationRef.current.scrollHeight;
            }
        } catch (readError) {
            console.warn("Stream reading interrupted", readError);
            break; 
        }
      }
    } catch (error) {
      console.error("Error fetching interpretation", error);
      setInterpretation("Xin lỗi, vũ trụ đang bận rộn. Vui lòng thử lại sau để nhận lời khuyên tổng hợp.");
    } finally {
      setIsInterpreting(false);
      abortControllerRef.current = null;
    }
  };

  // --- COMPONENTS ---

  const InstallModal = () => (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fadeIn">
      {/* Visual Hint Arrow for Android */}
      {!isIOS && (
        <div className="fixed top-2 right-2 md:top-4 md:right-4 z-50 animate-bounce">
            <div className="bg-mystic-accent text-mystic-900 px-3 py-1 rounded-lg font-bold text-sm shadow-[0_0_15px_rgba(251,191,36,0.8)] flex items-center gap-1">
                Bấm vào đây <ArrowUpRight className="w-5 h-5" />
            </div>
        </div>
      )}

      <div className="bg-mystic-900 border border-mystic-600 rounded-2xl w-full max-w-sm p-6 relative shadow-2xl">
        <button 
          onClick={() => setShowInstallModal(false)}
          className="absolute top-4 right-4 text-mystic-400 hover:text-white"
        >
          <X className="w-6 h-6" />
        </button>

        <h3 className="text-xl font-serif font-bold text-mystic-accent mb-4 text-center">
          Hướng dẫn Cài đặt
        </h3>

        <p className="text-sm text-center text-mystic-300 mb-6">
            Đây là Web App. Để tải về như app thường, bạn hãy làm theo các bước sau:
        </p>

        {isIOS ? (
          <div className="space-y-4 text-mystic-200">
            <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">1</span>
                <p className="text-sm">Bấm nút <strong>Chia sẻ</strong> <Share className="w-4 h-4 inline mx-1" /> ở dưới cùng màn hình.</p>
            </div>
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">2</span>
                <p className="text-sm">Chọn dòng <strong>"Thêm vào màn hình chính"</strong> (Add to Home Screen).</p>
            </div>
          </div>
        ) : (
          <div className="space-y-4 text-mystic-200">
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg border border-mystic-700">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">1</span>
                <p className="text-sm">Nhìn lên góc phải trên cùng, bấm vào dấu <strong>3 chấm</strong> <MoreVertical className="w-4 h-4 inline" />.</p>
            </div>
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg border border-mystic-700">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">2</span>
                <p className="text-sm">
                    Tìm và chọn dòng <br/> 
                    <strong>"Cài đặt ứng dụng"</strong> <br/>
                    hoặc <strong>"Thêm vào màn hình chính"</strong>.
                </p>
            </div>
          </div>
        )}

        <button 
          onClick={() => setShowInstallModal(false)}
          className="mt-6 w-full py-3 bg-mystic-700 hover:bg-mystic-600 rounded-lg text-white font-bold transition-all hover:scale-105"
        >
          Đã hiểu, tôi sẽ thử ngay
        </button>
      </div>
    </div>
  );

  // --- VIEWS ---

  const renderHome = () => (
    <div className="flex flex-col items-center justify-center min-h-screen px-4 py-10 max-w-4xl mx-auto text-center space-y-12 animate-fadeIn relative">
      {/* Install Button - Always Visible on Home */}
      <button 
        onClick={handleInstallClick}
        className="absolute top-4 right-4 md:top-8 md:right-8 flex items-center gap-2 bg-mystic-800 hover:bg-mystic-700 text-mystic-accent px-4 py-2 rounded-full text-sm border border-mystic-700 shadow-lg transition-all animate-bounce z-40"
      >
        <Download className="w-4 h-4" />
        Tải App
      </button>

      {showInstallModal && <InstallModal />}

      <div className="space-y-4">
        <h1 className="text-5xl md:text-7xl font-serif text-mystic-accent animate-float drop-shadow-[0_0_15px_rgba(251,191,36,0.5)]">
          Mystic Tarot
        </h1>
        <p className="text-mystic-200 text-lg md:text-xl font-light tracking-wide max-w-2xl mx-auto">
          Khám phá vận mệnh qua những lá bài. Hình ảnh trực quan, giải nghĩa tức thì.
        </p>
      </div>

      {/* Spread Selection */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full">
        {Object.entries(SPREAD_INFO).map(([key, info]) => (
          <button
            key={key}
            onClick={() => setSelectedSpread(key as SpreadType)}
            className={`p-6 rounded-2xl border transition-all duration-300 flex flex-col items-center gap-3 group
              ${selectedSpread === key 
                ? 'bg-mystic-800 border-mystic-accent shadow-[0_0_20px_rgba(114,75,150,0.5)] transform scale-105' 
                : 'bg-mystic-900/50 border-mystic-700 hover:bg-mystic-800 hover:border-mystic-500'
              }`}
          >
             <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl mb-2
                ${selectedSpread === key ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}
             `}>
               {info.count}
             </div>
             <h3 className="text-xl font-serif font-bold text-gray-100">{info.name}</h3>
             <p className="text-sm text-gray-400 font-light">{info.description}</p>
          </button>
        ))}
      </div>

      {/* Question Input */}
      <div className="w-full max-w-lg space-y-6">
        <div className="relative">
            <input
              type="text"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              placeholder="Bạn muốn hỏi điều gì? (Tuỳ chọn)"
              className="w-full bg-mystic-900/80 border-b-2 border-mystic-600 px-4 py-3 text-center text-lg text-mystic-100 placeholder-mystic-600 focus:outline-none focus:border-mystic-accent transition-colors"
            />
            <Sparkles className="absolute right-2 top-3 w-5 h-5 text-mystic-500 animate-pulse" />
        </div>

        <button
          onClick={startReading}
          className="group relative px-8 py-4 bg-gradient-to-r from-mystic-600 to-mystic-800 rounded-full text-white font-bold tracking-widest uppercase overflow-hidden transition-all hover:scale-105 hover:shadow-[0_0_30px_rgba(251,191,36,0.4)]"
        >
          <span className="relative z-10 flex items-center gap-2">
            Rút Bài
          </span>
          <div className="absolute inset-0 bg-gradient-to-r from-mystic-accent to-purple-600 opacity-0 group-hover:opacity-20 transition-opacity duration-300"></div>
        </button>
      </div>
    </div>
