      {/* Cards Display */}
      <div className="flex flex-wrap justify-center items-start gap-4 md:gap-6 mb-8">
        {drawnCards.map((data, index) => (
          <div key={`${data.card.id}-${index}`} className="flex flex-col items-center space-y-2">
            <div className="relative">
                {/* Position Label */}
                <div className={`absolute -top-8 left-0 w-full text-center transition-opacity duration-300 ${index <= revealedCount ? 'opacity-100' : 'opacity-0'}`}>
                    <span className="text-[10px] uppercase tracking-widest text-mystic-300 font-bold bg-mystic-900 px-2 py-1 rounded border border-mystic-700">
                        {data.positionName}
                    </span>
                </div>

                <div className={`${activeCardIndex === index ? 'ring-2 ring-mystic-accent ring-offset-2 ring-offset-mystic-900 rounded-xl' : ''} transition-all duration-300`}>
                  <Card 
                      data={data.card} 
                      isReversed={data.isReversed}
                      isRevealed={index < revealedCount}
                      index={index}
                      onClick={() => revealCard(index)}
                  />
                </div>
            </div>

            {/* Click Indicator */}
            {index === revealedCount && (
                 <div className="animate-bounce text-mystic-accent text-xs font-bold cursor-pointer bg-mystic-800/80 px-2 py-1 rounded-full" onClick={() => revealCard(index)}>
