            {!isInterpreting && interpretation && (
                <div className="mt-6 flex justify-center">
                    <button 
                        onClick={() => setView('home')}
                        className="px-8 py-3 bg-mystic-700 hover:bg-mystic-600 rounded-full text-white font-bold transition-all shadow-lg border border-mystic-500"
                    >
                        Xem quẻ mới
                    </button>
                </div>
            )}
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0f0a15] text-gray-200 font-sans selection:bg-mystic-accent selection:text-mystic-900">
      {view === 'home' && renderHome()}
      {view === 'shuffling' && renderShuffling()}
      {view === 'reading' && renderReading()}
    </div>
  );
};

