  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim());
});

self.addEventListener('fetch', (event) => {
  // Simple pass-through strategy for development/previews
  // Ensures we don't accidentally cache broken pages from the host
  event.respondWith(
    fetch(event.request).catch(() => {
        // Fail silently or handle offline if needed
    })
  );
});

import React, { useState, useEffect, useRef } from 'react';
import { FULL_DECK, SPREAD_INFO } from './constants';
import { SpreadType, DrawnCard, TarotCardData } from './types';
import { Card } from './components/Card';
import { interpretReading } from './services/geminiService';
import { Sparkles, RefreshCcw, Loader2, ArrowLeft, ScrollText, Download, X, MoreVertical, Share, ArrowUpRight } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'shuffling' | 'reading'>('home');
  const [selectedSpread, setSelectedSpread] = useState<SpreadType>(SpreadType.ONE_CARD);
  const [question, setQuestion] = useState('');
  const [drawnCards, setDrawnCards] = useState<DrawnCard[]>([]);
  const [revealedCount, setRevealedCount] = useState(0);
  const [interpretation, setInterpretation] = useState('');
  const [isInterpreting, setIsInterpreting] = useState(false);

  // PWA State
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showInstallModal, setShowInstallModal] = useState(false);
  const [isIOS, setIsIOS] = useState(false);

  // Track the most recently revealed card to show its meaning immediately
  const [activeCardIndex, setActiveCardIndex] = useState<number | null>(null);

  const interpretationRef = useRef<HTMLDivElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Detect iOS safely
    const isIosDevice = /iPad|iPhone|iPod/.test(navigator.userAgent);
    setIsIOS(isIosDevice);

    const handler = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
      console.log("Install prompt ready");
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (deferredPrompt) {
      deferredPrompt.prompt();
      deferredPrompt.userChoice.then((choiceResult: any) => {
        setDeferredPrompt(null);
      });
    } else {
      setShowInstallModal(true);
    }
  };

  // Shuffle and Draw Logic
  const startReading = () => {
    setView('shuffling');
    setDrawnCards([]);
    setRevealedCount(0);
    setInterpretation('');
    setActiveCardIndex(null);

    setTimeout(() => {
      drawCards();
      setView('reading');
    }, 2000);
  };

  const drawCards = () => {
    const spreadDetails = SPREAD_INFO[selectedSpread];
    const deck = [...FULL_DECK];
    const newDrawnCards: DrawnCard[] = [];

    // Fisher-Yates Shuffle
    for (let i = deck.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [deck[i], deck[j]] = [deck[j], deck[i]];
    }

    for (let i = 0; i < spreadDetails.count; i++) {
      newDrawnCards.push({
        card: deck[i],
        position: i,
        positionName: spreadDetails.positions[i],
        isReversed: false // No reversed cards per request
      });
    }
    setDrawnCards(newDrawnCards);
  };

  const revealCard = (index: number) => {
    if (index === revealedCount) {
      setRevealedCount(prev => prev + 1);
      setActiveCardIndex(index);
    } else if (index < revealedCount) {
      setActiveCardIndex(index);
    }
  };

  useEffect(() => {
    if (drawnCards.length > 0 && revealedCount === drawnCards.length && !isInterpreting && !interpretation) {
      fetchInterpretation();
    }
    return () => {
        if (abortControllerRef.current) abortControllerRef.current.abort();
    };
  }, [revealedCount, drawnCards]);

  const fetchInterpretation = async () => {
    setIsInterpreting(true);
    abortControllerRef.current = new AbortController();

    try {
      const stream = await interpretReading(question, drawnCards);
      const reader = stream.getReader();

      while (true) {
        if (abortControllerRef.current?.signal.aborted) {
            reader.cancel();
            break;
        }
        const { done, value } = await reader.read();
        if (done) break;
        setInterpretation(prev => prev + value);
      }
    } catch (error) {
      console.error("Error interpretation:", error);
      setInterpretation("Xin lỗi, vũ trụ đang bận rộn. Vui lòng xem ý nghĩa từng lá bài bên dưới.");
    } finally {
      setIsInterpreting(false);
      abortControllerRef.current = null;
    }
  };

  // --- COMPONENTS ---

  const InstallModal = () => (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/90 animate-fadeIn">
      {/* Visual Hint Arrow for Android */}
      {!isIOS && (
        <div className="fixed top-2 right-2 md:top-4 md:right-4 z-[110] animate-bounce">
            <div className="bg-mystic-accent text-mystic-900 px-3 py-1 rounded-lg font-bold text-sm shadow-xl flex items-center gap-1">
                Bấm vào đây <ArrowUpRight className="w-5 h-5" />
            </div>
        </div>
      )}

      <div className="bg-mystic-900 border border-mystic-700 rounded-2xl w-full max-w-sm p-6 relative shadow-2xl">
        <button 
          onClick={() => setShowInstallModal(false)}
          className="absolute top-4 right-4 text-mystic-400 hover:text-white p-2"
        >
          <X className="w-6 h-6" />
        </button>

        <h3 className="text-xl font-serif font-bold text-mystic-accent mb-4 text-center">
          Hướng dẫn Cài đặt
        </h3>

        <p className="text-sm text-center text-mystic-300 mb-6 px-2">
            Để sử dụng như một ứng dụng bình thường trên điện thoại, hãy thực hiện:
        </p>

        {isIOS ? (
          <div className="space-y-3 text-mystic-200">
            <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">1</span>
                <p className="text-sm">Bấm nút <strong>Chia sẻ</strong> <Share className="w-4 h-4 inline mx-1" /> ở dưới trình duyệt.</p>
            </div>
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">2</span>
                <p className="text-sm">Chọn <strong>"Thêm vào màn hình chính"</strong>.</p>
            </div>
          </div>
        ) : (
          <div className="space-y-3 text-mystic-200">
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">1</span>
                <p className="text-sm">Nhìn lên góc phải, chọn biểu tượng <strong>3 chấm</strong> <MoreVertical className="w-4 h-4 inline" />.</p>
            </div>
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">2</span>
                <p className="text-sm">Chọn <strong>"Cài đặt ứng dụng"</strong> hoặc <strong>"Thêm vào MH chính"</strong>.</p>
            </div>
          </div>
        )}

        <button 
          onClick={() => setShowInstallModal(false)}
          className="mt-6 w-full py-3 bg-mystic-600 hover:bg-mystic-500 rounded-lg text-white font-bold transition-all"
        >
          Đã hiểu
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-mystic-900 text-gray-200 font-sans selection:bg-mystic-accent selection:text-mystic-900">
      {showInstallModal && <InstallModal />}

      {view === 'home' && (
        <div className="flex flex-col items-center justify-center min-h-screen px-4 py-10 max-w-4xl mx-auto text-center space-y-12 animate-fadeIn relative">
          <button 
            onClick={handleInstallClick}
            className="fixed top-4 right-4 z-40 flex items-center gap-2 bg-mystic-800/80 text-mystic-accent px-4 py-2 rounded-full text-sm border border-mystic-700 shadow-lg"
          >
            <Download className="w-4 h-4" />
            Cài App
          </button>

          <div className="space-y-4">
            <h1 className="text-5xl md:text-7xl font-serif text-mystic-accent animate-float drop-shadow-xl">
              Mystic Tarot
            </h1>
            <p className="text-mystic-200 text-lg md:text-xl font-light max-w-2xl mx-auto">
              Khám phá vận mệnh qua những lá bài. Hình ảnh trực quan, giải nghĩa tức thì.
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full">
            {Object.entries(SPREAD_INFO).map(([key, info]) => (
              <button
                key={key}
                onClick={() => setSelectedSpread(key as SpreadType)}
                className={`p-6 rounded-2xl border transition-all duration-300 flex flex-col items-center gap-3
                  ${selectedSpread === key 
                    ? 'bg-mystic-800 border-mystic-accent shadow-xl transform scale-105' 
                    : 'bg-mystic-900/50 border-mystic-700 hover:bg-mystic-800'
                  }`}
              >
                 <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl mb-2
                    ${selectedSpread === key ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}
                 `}>
                   {info.count}
                 </div>
                 <h3 className="text-xl font-serif font-bold text-gray-100">{info.name}</h3>
                 <p className="text-sm text-gray-400 font-light">{info.description}</p>
              </button>
            ))}
          </div>

          <div className="w-full max-w-lg space-y-6">
            <input
              type="text"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              placeholder="Bạn muốn hỏi điều gì? (Tuỳ chọn)"
              className="w-full bg-mystic-900 border-b-2 border-mystic-600 px-4 py-3 text-center text-lg text-mystic-100 placeholder-mystic-600 focus:outline-none focus:border-mystic-accent"
            />
            <button
              onClick={startReading}
              className="px-10 py-4 bg-gradient-to-r from-mystic-600 to-mystic-800 rounded-full text-white font-bold tracking-widest uppercase hover:scale-105 transition-all shadow-xl"
            >
              Rút Bài
            </button>
          </div>
        </div>
      )}

      {view === 'shuffling' && (
        <div className="flex flex-col items-center justify-center min-h-screen">
           <div className="relative w-48 h-80">
              <div className="absolute inset-0 bg-mystic-800 rounded-xl border-2 border-mystic-500 animate-pulse"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-32 h-52 bg-gradient-to-br from-mystic-700 to-mystic-900 rounded-lg border-2 border-mystic-accent flex flex-col items-center justify-center shadow-2xl animate-bounce">
                     <RefreshCcw className="w-10 h-10 text-mystic-accent animate-spin mb-2" />
                     <span className="text-xs text-mystic-200 uppercase tracking-widest font-bold">Mystic</span>
                </div>
              </div>
           </div>
           <h2 className="mt-12 text-2xl font-serif text-mystic-100 font-bold">Đang xào bài...</h2>
        </div>
      )}

      {view === 'reading' && (
        <div className="min-h-screen flex flex-col p-4 md:p-8 max-w-7xl mx-auto pb-24 animate-fadeIn">
          <div className="flex items-center justify-between mb-6">
            <button onClick={() => setView('home')} className="flex items-center gap-2 text-mystic-400 hover:text-mystic-accent transition-colors">
