                      </div>
                  ))}
                </div>
             </div>
          )}

          {revealedCount === drawnCards.length && (
            <div className="bg-mystic-800/90 border border-mystic-700 rounded-2xl p-6 shadow-2xl animate-fadeIn">
                <div className="flex items-center gap-4 mb-4 border-b border-mystic-700 pb-4">
                    <Sparkles className="w-6 h-6 text-mystic-accent" />
                    <h3 className="text-xl font-serif text-mystic-100">Lời khuyên Tổng hợp</h3>
                    {isInterpreting && <Loader2 className="w-5 h-5 animate-spin text-mystic-500 ml-auto" />}
                </div>
                <div ref={interpretationRef} className="prose prose-invert max-w-none max-h-[400px] overflow-y-auto custom-scrollbar">
                    {interpretation ? (
