                </div>
                {!isInterpreting && interpretation && (
                    <div className="mt-6 flex justify-center">
                        <button onClick={() => setView('home')} className="px-8 py-3 bg-mystic-700 hover:bg-mystic-600 rounded-full text-white font-bold transition-all shadow-lg border border-mystic-500">
                            Xem quẻ mới
                        </button>
                    </div>
                )}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

