import React, { useState, useEffect, useRef } from 'react';
import { FULL_DECK, SPREAD_INFO } from './constants';
import { SpreadType, DrawnCard, TarotCardData } from './types';
import { Card } from './components/Card';
import { interpretReading } from './services/geminiService';
import { Sparkles, RefreshCcw, Loader2, ArrowLeft, ScrollText, Download, X, MoreVertical, Share, ArrowUpRight, Globe, Copy, Check, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'shuffling' | 'reading'>('home');
  const [selectedSpread, setSelectedSpread] = useState<SpreadType>(SpreadType.ONE_CARD);
  const [question, setQuestion] = useState('');
  const [drawnCards, setDrawnCards] = useState<DrawnCard[]>([]);
  const [revealedCount, setRevealedCount] = useState(0);
  const [interpretation, setInterpretation] = useState('');
  const [isInterpreting, setIsInterpreting] = useState(false);

  // PWA State
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showInstallModal, setShowInstallModal] = useState(false);
  const [isIOS, setIsIOS] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);

  // Track the most recently revealed card to show its meaning immediately
  const [activeCardIndex, setActiveCardIndex] = useState<number | null>(null);

  const interpretationRef = useRef<HTMLDivElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Detect iOS safely
    const isIosDevice = /iPad|iPhone|iPod/.test(navigator.userAgent);
    setIsIOS(isIosDevice);

    // Check if already installed/standalone
    const isStandaloneMode = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
    setIsStandalone(isStandaloneMode);

    const handler = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
      console.log("Install prompt ready");
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (deferredPrompt) {
      deferredPrompt.prompt();
      deferredPrompt.userChoice.then((choiceResult: any) => {
        setDeferredPrompt(null);
      });
    } else {
      setShowInstallModal(true);
    }
  };

  // Shuffle and Draw Logic
  const startReading = () => {
    setView('shuffling');
    setDrawnCards([]);
    setRevealedCount(0);
    setInterpretation('');
    setActiveCardIndex(null);

    setTimeout(() => {
      drawCards();
      setView('reading');
    }, 2000);
  };

  const drawCards = () => {
    const spreadDetails = SPREAD_INFO[selectedSpread];
    const deck = [...FULL_DECK];
    const newDrawnCards: DrawnCard[] = [];

    // Fisher-Yates Shuffle
    for (let i = deck.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [deck[i], deck[j]] = [deck[j], deck[i]];
    }

    for (let i = 0; i < spreadDetails.count; i++) {
      newDrawnCards.push({
        card: deck[i],
        position: i,
        positionName: spreadDetails.positions[i],
        isReversed: false // No reversed cards per request
      });
    }
    setDrawnCards(newDrawnCards);
  };

  const revealCard = (index: number) => {
    if (index === revealedCount) {
      setRevealedCount(prev => prev + 1);
      setActiveCardIndex(index);
    } else if (index < revealedCount) {
      setActiveCardIndex(index);
    }
  };

  useEffect(() => {
    if (drawnCards.length > 0 && revealedCount === drawnCards.length && !isInterpreting && !interpretation) {
      fetchInterpretation();
    }
    return () => {
        if (abortControllerRef.current) abortControllerRef.current.abort();
    };
  }, [revealedCount, drawnCards]);

  const fetchInterpretation = async () => {
    setIsInterpreting(true);
    abortControllerRef.current = new AbortController();

    try {
      const stream = await interpretReading(question, drawnCards);
      const reader = stream.getReader();

      while (true) {
        if (abortControllerRef.current?.signal.aborted) {
            reader.cancel();
            break;
        }
        const { done, value } = await reader.read();
        if (done) break;
        setInterpretation(prev => prev + value);
      }
    } catch (error) {
      console.error("Error interpretation:", error);
      setInterpretation("Xin lỗi, vũ trụ đang bận rộn. Vui lòng xem ý nghĩa từng lá bài bên dưới.");
    } finally {
      setIsInterpreting(false);
      abortControllerRef.current = null;
    }
  };

  // --- COMPONENTS ---

  const InstallModal = () => {
    const [copied, setCopied] = useState(false);
    const currentUrl = window.location.href;
    // Check if the URL is a blob URL (preview mode)
    const isBlobUrl = currentUrl.startsWith('blob:');

    const handleCopy = () => {
        navigator.clipboard.writeText(currentUrl);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/90 animate-fadeIn">
      {/* Visual Hint Arrow for Android */}
      {!isIOS && !isBlobUrl && (
        <div className="fixed top-2 right-2 md:top-4 md:right-4 z-[110] animate-bounce">
            <div className="bg-mystic-accent text-mystic-900 px-3 py-1 rounded-lg font-bold text-sm shadow-xl flex items-center gap-1">
                Bấm vào đây <ArrowUpRight className="w-5 h-5" />
            </div>
        </div>
      )}

      <div className="bg-mystic-900 border border-mystic-700 rounded-2xl w-full max-w-sm p-6 relative shadow-2xl overflow-y-auto max-h-[90vh]">
        <button 
          onClick={() => setShowInstallModal(false)}
          className="absolute top-4 right-4 text-mystic-400 hover:text-white p-2"
        >
          <X className="w-6 h-6" />
        </button>

        <h3 className="text-xl font-serif font-bold text-mystic-accent mb-4 text-center">
          Cài đặt về máy
        </h3>

        {isBlobUrl ? (
             <div className="bg-red-900/30 border border-red-700/50 p-3 rounded-lg mb-4 space-y-2">
                <div className="flex gap-3 items-start">
                    <AlertTriangle className="w-6 h-6 text-red-500 shrink-0 mt-0.5" />
                    <div>
                        <p className="text-sm font-bold text-red-200">Không thể chia sẻ Link này</p>
                        <p className="text-xs text-red-300 mt-1">
                            Bạn đang xem ở chế độ "Preview" (đường dẫn blob:...). Đây là link tạm thời và không thể mở trên thiết bị khác.
                        </p>
                        <p className="text-xs text-red-300 mt-2 italic">
                            Hãy Deploy (Xuất bản) ứng dụng để có đường link chính thức.
                        </p>
                    </div>
                </div>
            </div>
        ) : (
            <div className="bg-yellow-900/30 border border-yellow-700/50 p-3 rounded-lg mb-4 space-y-2">
                <div className="flex gap-3 items-start">
                    <Globe className="w-5 h-5 text-yellow-500 shrink-0 mt-0.5" />
                    <p className="text-xs text-yellow-200">
                        Nếu bạn đang ở trong Facebook/Zalo, hãy sao chép link dưới đây và mở bằng <strong>Chrome</strong> (Android) hoặc <strong>Safari</strong> (iOS).
                    </p>
                </div>

                <div className="flex items-center gap-2 bg-black/50 p-2 rounded border border-mystic-700 mt-2">
                    <input 
                        readOnly 
                        value={currentUrl} 
                        className="bg-transparent border-none text-mystic-300 text-xs w-full focus:outline-none truncate"
                    />
                    <button 
                        onClick={handleCopy}
                        className={`shrink-0 px-2 py-1 rounded text-xs font-bold transition-all flex items-center gap-1 ${copied ? 'bg-green-600 text-white' : 'bg-mystic-600 text-white hover:bg-mystic-500'}`}
                    >
                        {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
                        {copied ? 'Đã chép' : 'Sao chép'}
                    </button>
                </div>
            </div>
        )}

        {isIOS ? (
          <div className="space-y-3 text-mystic-200">
            <p className="text-sm font-bold text-center mb-2">Dành cho iPhone (Safari):</p>
            <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">1</span>
                <p className="text-sm">Bấm nút <strong>Chia sẻ</strong> <Share className="w-4 h-4 inline mx-1" /> ở dưới giữa màn hình.</p>
            </div>
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">2</span>
                <p className="text-sm">Kéo xuống chọn <strong>"Thêm vào MH chính"</strong> (Add to Home Screen).</p>
            </div>
          </div>
        ) : (
          <div className="space-y-3 text-mystic-200">
             <p className="text-sm font-bold text-center mb-2">Dành cho Android (Chrome):</p>
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">1</span>
                <p className="text-sm">Bấm vào dấu <strong>3 chấm</strong> <MoreVertical className="w-4 h-4 inline" /> ở góc phải trên cùng.</p>
            </div>
             <div className="flex items-start gap-3 bg-mystic-800 p-3 rounded-lg">
                <span className="bg-mystic-700 w-6 h-6 flex items-center justify-center rounded-full text-xs font-bold shrink-0">2</span>
                <p className="text-sm">Chọn <strong>"Cài đặt ứng dụng"</strong> hoặc <strong>"Thêm vào màn hình chính"</strong>.</p>
            </div>
          </div>
        )}

        <button 
          onClick={() => setShowInstallModal(false)}
          className="mt-6 w-full py-3 bg-mystic-600 hover:bg-mystic-500 rounded-lg text-white font-bold transition-all"
        >
          Đã hiểu
        </button>
      </div>
    </div>
  );
  };

  return (
    <div className="min-h-screen bg-mystic-900 text-gray-200 font-sans selection:bg-mystic-accent selection:text-mystic-900">
      {showInstallModal && <InstallModal />}

      {view === 'home' && (
        <div className="flex flex-col items-center justify-center min-h-screen px-4 py-10 max-w-4xl mx-auto text-center space-y-12 animate-fadeIn relative">
          {!isStandalone && (
            <button 
              onClick={handleInstallClick}
              className="fixed top-4 right-4 z-40 flex items-center gap-2 bg-mystic-800/80 text-mystic-accent px-4 py-2 rounded-full text-sm border border-mystic-700 shadow-lg hover:bg-mystic-700 transition-colors"
            >
              <Download className="w-4 h-4" />
              Cài App
            </button>
          )}

          <div className="space-y-4">
            <h1 className="text-5xl md:text-7xl font-serif text-mystic-accent animate-float drop-shadow-xl">
              Mystic Tarot
            </h1>
            <p className="text-mystic-200 text-lg md:text-xl font-light max-w-2xl mx-auto">
              Khám phá vận mệnh qua những lá bài. Hình ảnh trực quan, giải nghĩa tức thì.
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full">
            {Object.entries(SPREAD_INFO).map(([key, info]) => (
              <button
                key={key}
                onClick={() => setSelectedSpread(key as SpreadType)}
                className={`p-6 rounded-2xl border transition-all duration-300 flex flex-col items-center gap-3
                  ${selectedSpread === key 
                    ? 'bg-mystic-800 border-mystic-accent shadow-xl transform scale-105' 
                    : 'bg-mystic-900/50 border-mystic-700 hover:bg-mystic-800'
                  }`}
              >
                 <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl mb-2
                    ${selectedSpread === key ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}
                 `}>
                   {info.count}
                 </div>
                 <h3 className="text-xl font-serif font-bold text-gray-100">{info.name}</h3>
                 <p className="text-sm text-gray-400 font-light">{info.description}</p>
              </button>
            ))}
          </div>

          <div className="w-full max-w-lg space-y-6">
            <input
              type="text"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              placeholder="Bạn muốn hỏi điều gì? (Tuỳ chọn)"
              className="w-full bg-mystic-900 border-b-2 border-mystic-600 px-4 py-3 text-center text-lg text-mystic-100 placeholder-mystic-600 focus:outline-none focus:border-mystic-accent"
            />
            <button
              onClick={startReading}
              className="px-10 py-4 bg-gradient-to-r from-mystic-600 to-mystic-800 rounded-full text-white font-bold tracking-widest uppercase hover:scale-105 transition-all shadow-xl"
            >
              Rút Bài
            </button>
          </div>
        </div>
      )}

      {view === 'shuffling' && (
        <div className="flex flex-col items-center justify-center min-h-screen">
           <div className="relative w-48 h-80">
              <div className="absolute inset-0 bg-mystic-800 rounded-xl border-2 border-mystic-500 animate-pulse"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-32 h-52 bg-gradient-to-br from-mystic-700 to-mystic-900 rounded-lg border-2 border-mystic-accent flex flex-col items-center justify-center shadow-2xl animate-bounce">
                     <RefreshCcw className="w-10 h-10 text-mystic-accent animate-spin mb-2" />
                     <span className="text-xs text-mystic-200 uppercase tracking-widest font-bold">Mystic</span>
                </div>
              </div>
           </div>
           <h2 className="mt-12 text-2xl font-serif text-mystic-100 font-bold">Đang xào bài...</h2>
        </div>
      )}

      {view === 'reading' && (
        <div className="min-h-screen flex flex-col p-4 md:p-8 max-w-7xl mx-auto pb-24 animate-fadeIn">
          <div className="flex items-center justify-between mb-6">
            <button onClick={() => setView('home')} className="flex items-center gap-2 text-mystic-400 hover:text-mystic-accent transition-colors">
                <ArrowLeft className="w-4 h-4" /> Trở về
            </button>
            <h2 className="text-lg md:text-xl font-serif text-white text-center truncate px-2">
                {question || "Thông điệp vũ trụ"}
            </h2>
            <div className="w-20"></div> 
          </div>

          <div className="flex flex-wrap justify-center items-start gap-4 md:gap-6 mb-8">
            {drawnCards.map((data, index) => (
              <div key={index} className="flex flex-col items-center space-y-2">
                <div className="relative">
                    <div className={`absolute -top-8 left-0 w-full text-center transition-opacity duration-300 ${index <= revealedCount ? 'opacity-100' : 'opacity-0'}`}>
                        <span className="text-[10px] uppercase tracking-widest text-mystic-300 font-bold bg-mystic-900 px-2 py-1 rounded border border-mystic-700">
                            {data.positionName}
                        </span>
                    </div>
                    <div className={`${activeCardIndex === index ? 'ring-2 ring-mystic-accent rounded-xl' : ''}`}>
                      <Card data={data.card} isReversed={data.isReversed} isRevealed={index < revealedCount} index={index} onClick={() => revealCard(index)} />
                    </div>
                </div>
                {index === revealedCount && (
                     <div className="animate-bounce text-mystic-accent text-xs font-bold bg-mystic-800/80 px-2 py-1 rounded-full cursor-pointer" onClick={() => revealCard(index)}>
                        👆 Lật bài
                     </div>
                )}
              </div>
            ))}
          </div>

          {revealedCount > 0 && (
             <div className="w-full max-w-4xl mx-auto mb-8 space-y-4">
                <div className="flex items-center gap-2 mb-2 px-2">
                     <ScrollText className="w-5 h-5 text-mystic-accent" />
                     <h3 className="text-lg font-serif text-mystic-200">Chi tiết lá bài</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {drawnCards.slice(0, revealedCount).map((cardData, idx) => (
                      <div key={idx} className={`bg-mystic-800/80 border rounded-lg p-4 transition-all ${activeCardIndex === idx ? 'border-mystic-accent bg-mystic-800' : 'border-mystic-700'}`} onClick={() => setActiveCardIndex(idx)}>
                          <div className="flex items-start gap-3">
                              <div className={`mt-1 w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${activeCardIndex === idx ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}`}>
                                  {idx + 1}
                              </div>
                              <div>
                                  <h4 className="font-serif font-bold text-white">{cardData.card.name_vi}</h4>
                                  <p className="text-xs text-mystic-400 uppercase tracking-wider mb-2">{cardData.positionName}</p>
                                  <p className="text-mystic-200 text-sm leading-relaxed">{cardData.card.meaning_upright}</p>
                              </div>
                          </div>
                      </div>
                  ))}
                </div>
             </div>
          )}

          {revealedCount === drawnCards.length && (
            <div className="bg-mystic-800/90 border border-mystic-700 rounded-2xl p-6 shadow-2xl animate-fadeIn">
                <div className="flex items-center gap-4 mb-4 border-b border-mystic-700 pb-4">
                    <Sparkles className="w-6 h-6 text-mystic-accent" />
                    <h3 className="text-xl font-serif text-mystic-100">Lời khuyên Tổng hợp</h3>
                    {isInterpreting && <Loader2 className="w-5 h-5 animate-spin text-mystic-500 ml-auto" />}
                </div>
                <div ref={interpretationRef} className="prose prose-invert max-w-none max-h-[400px] overflow-y-auto custom-scrollbar">
                    {interpretation ? (
                         <div className="whitespace-pre-wrap font-serif text-mystic-100 leading-relaxed text-base md:text-lg">
                            {interpretation}
                         </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-8 text-mystic-500 gap-3">
                            <Loader2 className="w-6 h-6 animate-spin" /> 
                            <span className="italic">Đang kết nối năng lượng...</span>
                        </div>
                    )}
                </div>
                {!isInterpreting && interpretation && (
                    <div className="mt-6 flex justify-center">
                        <button onClick={() => setView('home')} className="px-8 py-3 bg-mystic-700 hover:bg-mystic-600 rounded-full text-white font-bold transition-all shadow-lg border border-mystic-500">
                            Xem quẻ mới
                        </button>
                    </div>
                )}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { ReactNode, ErrorInfo, Component } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// Fix: Use React.Component explicitly to ensure TypeScript correctly identifies 'props' and its types
class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("App crashed:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: 20, color: '#fff', backgroundColor: '#1a1025', height: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
          <h1 style={{ color: '#fbbf24' }}>Đã xảy ra lỗi hệ thống</h1>
          <p>Ứng dụng đã gặp sự cố. Vui lòng tải lại trang.</p>
          <p style={{ color: '#999', fontSize: '0.8rem', marginTop: 10 }}>{this.state.error?.message}</p>
          <button 
            onClick={() => window.location.reload()}
            style={{ marginTop: 20, padding: '10px 20px', background: '#fbbf24', color: '#000', border: 'none', borderRadius: 5, cursor: 'pointer' }}
          >
            Tải lại trang
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  </React.StrictMode>
);

import React, { useState, useEffect, useRef } from 'react';
import { FULL_DECK, SPREAD_INFO } from './constants';
import { SpreadType, DrawnCard, TarotCardData } from './types';
import { Card } from './components/Card';
import { interpretReading } from './services/geminiService';
import { Sparkles, RefreshCcw, Loader2, ArrowLeft, ScrollText, Download, X, MoreVertical, Share, ArrowUpRight, Globe, Copy, Check, Smartphone, Monitor } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'shuffling' | 'reading'>('home');
  const [selectedSpread, setSelectedSpread] = useState<SpreadType>(SpreadType.ONE_CARD);
  const [question, setQuestion] = useState('');
  const [drawnCards, setDrawnCards] = useState<DrawnCard[]>([]);
  const [revealedCount, setRevealedCount] = useState(0);
  const [interpretation, setInterpretation] = useState('');
  const [isInterpreting, setIsInterpreting] = useState(false);

  // PWA State
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showInstallModal, setShowInstallModal] = useState(false);
  const [isIOS, setIsIOS] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);
  const [isMobileUserAgent, setIsMobileUserAgent] = useState(false);

  // Track the most recently revealed card to show its meaning immediately
  const [activeCardIndex, setActiveCardIndex] = useState<number | null>(null);

  const interpretationRef = useRef<HTMLDivElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Detect iOS safely
    const isIosDevice = /iPad|iPhone|iPod/.test(navigator.userAgent);
    setIsIOS(isIosDevice);

    // Detect generic mobile
    const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
    setIsMobileUserAgent(isMobile);

    // Check if already installed/standalone
    const isStandaloneMode = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
    setIsStandalone(isStandaloneMode);

    const handler = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
      console.log("Install prompt ready");
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    // If browser supports native install prompt, use it
    if (deferredPrompt) {
      deferredPrompt.prompt();
      deferredPrompt.userChoice.then((choiceResult: any) => {
        setDeferredPrompt(null);
      });
    } else {
      // Otherwise show manual instructions
      setShowInstallModal(true);
    }
  };

  // Shuffle and Draw Logic
  const startReading = () => {
    setView('shuffling');
    setDrawnCards([]);
    setRevealedCount(0);
    setInterpretation('');
    setActiveCardIndex(null);

    setTimeout(() => {
      drawCards();
      setView('reading');
    }, 2000);
  };

  const drawCards = () => {
    const spreadDetails = SPREAD_INFO[selectedSpread];
    const deck = [...FULL_DECK];
    const newDrawnCards: DrawnCard[] = [];

    // Fisher-Yates Shuffle
    for (let i = deck.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [deck[i], deck[j]] = [deck[j], deck[i]];
    }

    for (let i = 0; i < spreadDetails.count; i++) {
      newDrawnCards.push({
        card: deck[i],
        position: i,
        positionName: spreadDetails.positions[i],
        isReversed: false // No reversed cards per request
      });
    }
    setDrawnCards(newDrawnCards);
  };

  const revealCard = (index: number) => {
    if (index === revealedCount) {
      setRevealedCount(prev => prev + 1);
      setActiveCardIndex(index);
    } else if (index < revealedCount) {
      setActiveCardIndex(index);
    }
  };

  useEffect(() => {
    if (drawnCards.length > 0 && revealedCount === drawnCards.length && !isInterpreting && !interpretation) {
      fetchInterpretation();
    }
    return () => {
        if (abortControllerRef.current) abortControllerRef.current.abort();
    };
  }, [revealedCount, drawnCards]);

  const fetchInterpretation = async () => {
    setIsInterpreting(true);
    abortControllerRef.current = new AbortController();

    try {
      const stream = await interpretReading(question, drawnCards);
      const reader = stream.getReader();

      while (true) {
        if (abortControllerRef.current?.signal.aborted) {
            reader.cancel();
            break;
        }
        const { done, value } = await reader.read();
        if (done) break;
        setInterpretation(prev => prev + value);
      }
    } catch (error) {
      console.error("Error interpretation:", error);
      setInterpretation("Xin lỗi, vũ trụ đang bận rộn. Vui lòng xem ý nghĩa từng lá bài bên dưới.");
    } finally {
      setIsInterpreting(false);
      abortControllerRef.current = null;
    }
  };

  // --- COMPONENTS ---

  const InstallModal = () => {
    const [copied, setCopied] = useState(false);
    const currentUrl = window.location.href;
    const isBlobUrl = currentUrl.startsWith('blob:');

