                     </div>
                )}
              </div>
            ))}
          </div>

          {revealedCount > 0 && (
             <div className="w-full max-w-4xl mx-auto mb-8 space-y-4">
                <div className="flex items-center gap-2 mb-2 px-2">
                     <ScrollText className="w-5 h-5 text-mystic-accent" />
                     <h3 className="text-lg font-serif text-mystic-200">Chi tiết lá bài</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {drawnCards.slice(0, revealedCount).map((cardData, idx) => (
                      <div key={idx} className={`bg-mystic-800/80 border rounded-lg p-4 transition-all ${activeCardIndex === idx ? 'border-mystic-accent bg-mystic-800' : 'border-mystic-700'}`} onClick={() => setActiveCardIndex(idx)}>
                          <div className="flex items-start gap-3">
                              <div className={`mt-1 w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${activeCardIndex === idx ? 'bg-mystic-accent text-mystic-900' : 'bg-mystic-700 text-mystic-300'}`}>
                                  {idx + 1}
                              </div>
                              <div>
                                  <h4 className="font-serif font-bold text-white">{cardData.card.name_vi}</h4>
                                  <p className="text-xs text-mystic-400 uppercase tracking-wider mb-2">{cardData.positionName}</p>
                                  <p className="text-mystic-200 text-sm leading-relaxed">{cardData.card.meaning_upright}</p>
                              </div>
                          </div>
                      </div>
                  ))}
                </div>
             </div>
          )}

          {revealedCount === drawnCards.length && (
            <div className="bg-mystic-800/90 border border-mystic-700 rounded-2xl p-6 shadow-2xl animate-fadeIn">
                <div className="flex items-center gap-4 mb-4 border-b border-mystic-700 pb-4">
                    <Sparkles className="w-6 h-6 text-mystic-accent" />
                    <h3 className="text-xl font-serif text-mystic-100">Lời khuyên Tổng hợp</h3>
                    {isInterpreting && <Loader2 className="w-5 h-5 animate-spin text-mystic-500 ml-auto" />}
                </div>
                <div ref={interpretationRef} className="prose prose-invert max-w-none max-h-[400px] overflow-y-auto custom-scrollbar">
                    {interpretation ? (
                         <div className="whitespace-pre-wrap font-serif text-mystic-100 leading-relaxed text-base md:text-lg">
                            {interpretation}
                         </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-8 text-mystic-500 gap-3">
                            <Loader2 className="w-6 h-6 animate-spin" /> 
