class SoundService {
  private ctx: AudioContext | null = null;
  private isMuted: boolean = false;
  private noiseBuffer: AudioBuffer | null = null;

  constructor() {
    // Initialize AudioContext lazily or on user interaction to comply with browser policies
  }

  private init() {
    if (!this.ctx) {
      const Ctx = window.AudioContext || (window as any).webkitAudioContext;
      if (Ctx) {
        this.ctx = new Ctx();
        this.createNoiseBuffer();
      }
    }
    if (this.ctx && this.ctx.state === 'suspended') {
      this.ctx.resume().catch(() => {});
    }
  }

  private createNoiseBuffer() {
    if (!this.ctx) return;
    const bufferSize = this.ctx.sampleRate * 2; // 2 seconds of noise
    this.noiseBuffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const output = this.noiseBuffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      output[i] = Math.random() * 2 - 1;
    }
  }

  public toggleMute() {
    this.isMuted = !this.isMuted;
    return this.isMuted;
  }

  public getMuteState() {
    return this.isMuted;
  }

  public resumeContext() {
    this.init();
  }

  // --- SOUND EFFECTS ---

  // 1. Gentle Card Flip / Whoosh
  public playFlip() {
    if (this.isMuted || !this.ctx || !this.noiseBuffer) return;

    const t = this.ctx.currentTime;
    const source = this.ctx.createBufferSource();
    source.buffer = this.noiseBuffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1200, t);
    filter.frequency.exponentialRampToValueAtTime(300, t + 0.15);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.3, t);
    gain.gain.exponentialRampToValueAtTime(0.01, t + 0.15);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);

    source.start(t);
    source.stop(t + 0.2);
  }

  // 2. Shuffling Sound (Multiple rapid flips)
  public playShuffle() {
    if (this.isMuted || !this.ctx) return;
    this.resumeContext();

    let count = 0;
    const interval = setInterval(() => {
      this.playFlip();
      count++;
      if (count > 5) clearInterval(interval);
    }, 120);
  }

  // 3. Mystic Chime (When interpretation is ready)
  public playChime() {
    if (this.isMuted || !this.ctx) return;

    const t = this.ctx.currentTime;
    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.15, t + 0.5); // Slow attack
    gain.gain.exponentialRampToValueAtTime(0.001, t + 4.0); // Long decay

    // Create a mystic chord (Pentatonic: C, D, E, G, A)
    const frequencies = [523.25, 659.25, 783.99, 1046.50]; // C5, E5, G5, C6

    frequencies.forEach((freq, i) => {
        if (!this.ctx) return;
        const osc = this.ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, t);

        // Add slight detune for richness
        osc.detune.setValueAtTime(i * 2, t); 

        osc.connect(gain);
        osc.start(t);
        osc.stop(t + 4.0);
    });

    // Add a sparkle effect (high frequency twinkling)
    const sparkleOsc = this.ctx.createOscillator();
    sparkleOsc.type = 'triangle';
    sparkleOsc.frequency.setValueAtTime(2000, t);
    sparkleOsc.frequency.linearRampToValueAtTime(0, t + 1);

    const sparkleGain = this.ctx.createGain();
    sparkleGain.gain.setValueAtTime(0.05, t);
    sparkleGain.gain.exponentialRampToValueAtTime(0.001, t + 1);

    sparkleOsc.connect(sparkleGain);
    sparkleGain.connect(this.ctx.destination);
    sparkleOsc.start(t);
    sparkleOsc.stop(t + 1);

    gain.connect(this.ctx.destination);
  }

  // 4. Reveal Click (Sharper sound)
  public playReveal() {
     if (this.isMuted || !this.ctx) return;
     this.playFlip();

     // Add a little "ding"
     const t = this.ctx.currentTime;
     const osc = this.ctx.createOscillator();
     osc.type = 'sine';
     osc.frequency.setValueAtTime(880, t); // A5
     osc.frequency.exponentialRampToValueAtTime(440, t + 0.1);

     const gain = this.ctx.createGain();
     gain.gain.setValueAtTime(0.05, t);
     gain.gain.exponentialRampToValueAtTime(0.001, t + 0.1);

     osc.connect(gain);
     gain.connect(this.ctx.destination);
     osc.start(t);
     osc.stop(t + 0.1);
  }
}

