import { GoogleGenAI } from "@google/genai";
import { DrawnCard } from '../types';

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    // Guidelines: The API key must be obtained exclusively from the environment variable process.env.API_KEY.
    // Assume this variable is pre-configured, valid, and accessible.
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

export const interpretReading = async (
  question: string,
  drawnCards: DrawnCard[]
): Promise<ReadableStream<string>> => {
  const client = getClient();
  const modelId = "gemini-3-flash-preview";

  const cardsDescription = drawnCards.map((c, index) => 
    `${index + 1}. Vị trí: ${c.positionName}
     - Lá bài: ${c.card.name_vi} (${c.card.name_en}) [${c.isReversed ? 'Ngược' : 'Xuôi'}]
     - Ý nghĩa cơ bản: ${c.isReversed ? c.card.meaning_reversed : c.card.meaning_upright}`
  ).join('\n');

  const systemInstruction = `
    Bạn là một Tarot Reader chuyên nghiệp, sâu sắc và tận tâm.

    Nhiệm vụ của bạn gồm 2 phần rõ ràng:
    1. PHÂN TÍCH CHI TIẾT TỪNG LÁ BÀI:
       - Đi sâu vào ý nghĩa của từng lá bài cụ thể trong bối cảnh của vị trí nó xuất hiện (ví dụ: Tại sao lá The Fool lại ở vị trí Quá Khứ?).
       - Giải thích hình ảnh hoặc biểu tượng nổi bật của lá bài nếu liên quan đến câu hỏi.

    2. TỔNG HỢP VÀ LỜI KHUYÊN:
       - Kết nối các lá bài lại với nhau (tìm các mẫu hình, ví dụ: nhiều lá cùng bộ Kiếm, nhiều lá Ẩn Chính...).
       - Đưa ra lời khuyên hành động cụ thể cho người hỏi.

    Phong cách:
    - Giọng văn huyền bí, nhẹ nhàng nhưng thực tế và mang tính chữa lành.
    - Trình bày rõ ràng, tách đoạn để dễ đọc trên điện thoại.
    - Ngôn ngữ: Tiếng Việt.
  `;

  const userPrompt = `
    Câu hỏi của người xem: "${question || "Xem tổng quan vận mệnh/lời khuyên hiện tại"}"

    Các lá bài đã rút được theo trải bài:
    ${cardsDescription}

    Hãy bắt đầu buổi xem bài ngay.
  `;

  try {
    const responseStream = await client.models.generateContentStream({
      model: modelId,
      contents: userPrompt,
      config: {
        temperature: 0.7,
        systemInstruction: systemInstruction,
      }
    });

    return new ReadableStream({
      async start(controller) {
        for await (const chunk of responseStream) {
          const text = chunk.text;
          if (text) {
            controller.enqueue(text);
          }
        }
        controller.close();
      }
    });

  } catch (error) {
    console.error("Error generating tarot reading:", error);
    return new ReadableStream({
        start(controller) {
            controller.enqueue("Không thể kết nối với Vũ trụ (Lỗi kết nối hoặc thiếu API Key). Tuy nhiên, bạn vẫn có thể tự chiêm nghiệm qua ý nghĩa các lá bài đã hiện.");
            controller.close();
        }
    });
  }
};

class SoundService {
  private ctx: AudioContext | null = null;
  private isMuted: boolean = false;
  private noiseBuffer: AudioBuffer | null = null;

  constructor() {
    // Initialize AudioContext lazily on user interaction
  }

  private init() {
    if (!this.ctx) {
      const Ctx = window.AudioContext || (window as any).webkitAudioContext;
      if (Ctx) {
        this.ctx = new Ctx();
        this.createNoiseBuffer();
      }
    }
    if (this.ctx && this.ctx.state === 'suspended') {
      this.ctx.resume().catch(() => {});
    }
  }

  private createNoiseBuffer() {
    if (!this.ctx) return;
    const bufferSize = this.ctx.sampleRate * 2;
    this.noiseBuffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const output = this.noiseBuffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      output[i] = Math.random() * 2 - 1;
    }
  }

  public toggleMute() {
    this.isMuted = !this.isMuted;
    return this.isMuted;
  }

  public getMuteState() {
    return this.isMuted;
  }

  public resumeContext() {
    this.init();
  }

  // --- SOUND EFFECTS ---

  /**
   * Phỏng đoán tiếng lật giấy/bài (Organic Paper Flip)
   * Sử dụng Bandpass filter để tạo độ "giòn" của giấy
   */
  public playFlip() {
    if (this.isMuted || !this.ctx || !this.noiseBuffer) return;

    const t = this.ctx.currentTime;
    const source = this.ctx.createBufferSource();
    source.buffer = this.noiseBuffer;

    // Filter tạo chất âm "giấy" (tập trung vào dải trung và cao)
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(1500, t);
    filter.Q.setValueAtTime(1, t);
    filter.frequency.exponentialRampToValueAtTime(800, t + 0.1);

    const gain = this.ctx.createGain();
    // Envelope tạo tiếng "sột soạt" nhanh
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.2, t + 0.01); // Attack cực nhanh
    gain.gain.linearRampToValueAtTime(0.05, t + 0.05); // Giảm nhẹ ở giữa
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.15); // Kết thúc

    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);

    source.start(t);
    source.stop(t + 0.2);
  }

  /**
   * Tiếng xào bài (Shuffling)
   * Nhiều tiếng lật nhẹ liên tiếp với cao độ thay đổi nhẹ
   */
  public playShuffle() {
    if (this.isMuted || !this.ctx) return;
    this.resumeContext();

    let count = 0;
    const interval = setInterval(() => {
      this.playFlip();
      count++;
      if (count > 8) clearInterval(interval);
    }, 80); // Tốc độ nhanh hơn để giống tiếng xào bài
  }

  /**
   * Tiếng lật bài/mở trang sách rõ ràng hơn (Clear Reveal)
   * Thêm một chút âm trầm để tạo độ nặng của bìa sách/bài dày
   */
  public playReveal() {
    if (this.isMuted || !this.ctx || !this.noiseBuffer) return;

    const t = this.ctx.currentTime;

    // Thành phần "Sột soạt" (Giấy)
    const source = this.ctx.createBufferSource();
    source.buffer = this.noiseBuffer;
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(2000, t);
    filter.frequency.exponentialRampToValueAtTime(400, t + 0.2);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.3, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.25);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);
    source.start(t);

    // Thành phần "Cạch" nhẹ (Tiếng thẻ bài chạm bàn)
    const tapOsc = this.ctx.createOscillator();
    tapOsc.type = 'triangle';
    tapOsc.frequency.setValueAtTime(150, t);
    tapOsc.frequency.exponentialRampToValueAtTime(40, t + 0.05);

    const tapGain = this.ctx.createGain();
    tapGain.gain.setValueAtTime(0.1, t);
    tapGain.gain.exponentialRampToValueAtTime(0.001, t + 0.05);

    tapOsc.connect(tapGain);
    tapGain.connect(this.ctx.destination);
    tapOsc.start(t);
    tapOsc.stop(t + 0.05);
  }

  /**
   * Tiếng chuông huyền bí khi có kết quả
   */
  public playChime() {
    if (this.isMuted || !this.ctx) return;

    const t = this.ctx.currentTime;
    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.1, t + 0.8); 
    gain.gain.exponentialRampToValueAtTime(0.001, t + 5.0); 

    const frequencies = [440, 554.37, 659.25, 880]; // Hợp âm A major tinh tế

    frequencies.forEach((freq, i) => {
        if (!this.ctx) return;
        const osc = this.ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, t);
        osc.detune.setValueAtTime(i * 3, t); 

        osc.connect(gain);
        osc.start(t);
        osc.stop(t + 5.0);
    });

    gain.connect(this.ctx.destination);
  }
}

