class SoundService {
  private ctx: AudioContext | null = null;
  private isMuted: boolean = false;
  private noiseBuffer: AudioBuffer | null = null;

  constructor() {}

  private init() {
    if (!this.ctx) {
      const Ctx = window.AudioContext || (window as any).webkitAudioContext;
      if (Ctx) {
        this.ctx = new Ctx();
        this.createNoiseBuffer();
      }
    }
    if (this.ctx && this.ctx.state === 'suspended') {
      this.ctx.resume().catch(() => {});
    }
  }

  private createNoiseBuffer() {
    if (!this.ctx) return;
    const bufferSize = this.ctx.sampleRate * 2;
    this.noiseBuffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const output = this.noiseBuffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      output[i] = Math.random() * 2 - 1;
    }
  }

  public toggleMute() {
    this.isMuted = !this.isMuted;
    return this.isMuted;
  }

  public resumeContext() {
    this.init();
  }

  /**
   * Âm thanh lật bài "Huyền bí" (Mystical Flip)
   * Kết hợp giữa tiếng chạm nhẹ và một chút ngân vang của tinh thể
   */
  public playFlip() {
    if (this.isMuted || !this.ctx) return;

    const t = this.ctx.currentTime;

    // 1. Tiếng "chạm" dịu nhẹ (Soft Thud)
    const osc1 = this.ctx.createOscillator();
    osc1.type = 'sine';
    osc1.frequency.setValueAtTime(120, t);
    osc1.frequency.exponentialRampToValueAtTime(60, t + 0.1);

    const g1 = this.ctx.createGain();
    g1.gain.setValueAtTime(0.05, t);
    g1.gain.exponentialRampToValueAtTime(0.001, t + 0.1);

    osc1.connect(g1);
    g1.connect(this.ctx.destination);
    osc1.start(t);
    osc1.stop(t + 0.1);

    // 2. Tiếng "Sparkle" huyền bí (Crystal Sparkle)
    const osc2 = this.ctx.createOscillator();
    osc2.type = 'sine';
    osc2.frequency.setValueAtTime(2200, t);
    osc2.frequency.exponentialRampToValueAtTime(3500, t + 0.2);

    const g2 = this.ctx.createGain();
    g2.gain.setValueAtTime(0, t);
    g2.gain.linearRampToValueAtTime(0.03, t + 0.02);
    g2.gain.exponentialRampToValueAtTime(0.001, t + 0.3);

    osc2.connect(g2);
    g2.connect(this.ctx.destination);
    osc2.start(t);
    osc2.stop(t + 0.3);
  }

  /**
   * Tiếng xào bài "Dịu êm" (Ethereal Shuffle)
   * Tạo cảm giác như dòng chảy năng lượng thay vì tiếng giấy khô
   */
  public playShuffle() {
    if (this.isMuted || !this.ctx) return;
    this.resumeContext();

    let count = 0;
    const interval = setInterval(() => {
      this.playFlip();
      // Thêm một âm "gió" nhẹ lồng vào
      this.playAir(0.05);
      count++;
      if (count > 6) clearInterval(interval);
    }, 150);
  }

  private playAir(duration: number) {
    if (!this.ctx || !this.noiseBuffer) return;
    const t = this.ctx.currentTime;
    const source = this.ctx.createBufferSource();
    source.buffer = this.noiseBuffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(1000, t);
    filter.Q.setValueAtTime(0.5, t);

    const g = this.ctx.createGain();
    g.gain.setValueAtTime(0, t);
    g.gain.linearRampToValueAtTime(0.02, t + duration/2);
    g.gain.exponentialRampToValueAtTime(0.001, t + duration);

    source.connect(filter);
    filter.connect(g);
    g.connect(this.ctx.destination);
    source.start(t);
    source.stop(t + duration);
  }

  /**
   * Tiếng lật bài rõ ràng (Mystic Reveal)
   * Âm thanh ngân vang dài hơn, báo hiệu sự hé lộ của định mệnh
   */
  public playReveal() {
    if (this.isMuted || !this.ctx) return;
    this.playFlip();

    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(880, t); // Nốt A5

    const g = this.ctx.createGain();
    g.gain.setValueAtTime(0, t);
    g.gain.linearRampToValueAtTime(0.05, t + 0.05);
    g.gain.exponentialRampToValueAtTime(0.001, t + 1.2);

    osc.connect(g);
    g.connect(this.ctx.destination);
    osc.start(t);
    osc.stop(t + 1.2);
  }

  /**
   * Tiếng chuông vũ trụ (Celestial Chime)
   * Sử dụng hợp âm treo (Suspended Chord) để tạo sự kỳ ảo và chưa dứt
   */
  public playChime() {
    if (this.isMuted || !this.ctx) return;

    const t = this.ctx.currentTime;
    const masterGain = this.ctx.createGain();
    masterGain.gain.setValueAtTime(0, t);
    masterGain.gain.linearRampToValueAtTime(0.12, t + 1.0); 
    masterGain.gain.exponentialRampToValueAtTime(0.001, t + 6.0); 

    // Hợp âm Asus2 (A, B, E) - Tạo cảm giác bay bổng, huyền bí
    const freqs = [220, 246.94, 329.63, 440, 659.25, 987.77]; 

    freqs.forEach((f, i) => {
      if (!this.ctx) return;
      const osc = this.ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(f, t);

      // Thêm một chút Vibrato nhẹ để âm thanh "sống" hơn
      const lfo = this.ctx.createOscillator();
      lfo.frequency.setValueAtTime(2 + Math.random(), t);
      const lfoGain = this.ctx.createGain();
      lfoGain.gain.setValueAtTime(2, t);
      lfo.connect(lfoGain);
      lfoGain.connect(osc.frequency);

      osc.connect(masterGain);
      lfo.start(t);
      osc.start(t + (i * 0.05)); // Đánh hợp âm rải nhẹ (Arpeggio)
      osc.stop(t + 6.0);
      lfo.stop(t + 6.0);
    });

    masterGain.connect(this.ctx.destination);
  }
}

