        this.createNoiseBuffer();
      }
    }
    if (this.ctx && this.ctx.state === 'suspended') {
      this.ctx.resume().catch(() => {});
    }
  }

  private createNoiseBuffer() {
    if (!this.ctx) return;
    const bufferSize = this.ctx.sampleRate * 2;
    this.noiseBuffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const output = this.noiseBuffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      // White noise base
      output[i] = Math.random() * 2 - 1;
    }
  }

  public toggleMute() {
    this.isMuted = !this.isMuted;
    return this.isMuted;
  }

  public resumeContext() {
    this.init();
  }

  /**
   * Tiếng lật trang giấy (Organic Page Flip)
   * Sử dụng Bandpass filter để tạo độ nhám của giấy
   */
  public playFlip() {
    if (this.isMuted || !this.ctx || !this.noiseBuffer) return;

    const t = this.ctx.currentTime;
    const source = this.ctx.createBufferSource();
    source.buffer = this.noiseBuffer;

    // Filter mô phỏng chất âm của giấy (dải trung ấm)
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(1200, t);
    filter.Q.setValueAtTime(1.5, t);
    // Tần số giảm dần mô phỏng tiếng giấy lướt qua
    filter.frequency.exponentialRampToValueAtTime(600, t + 0.15);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.15, t + 0.02); // Tấn công mềm
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.2); // Kết thúc êm

    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);

    source.start(t);
    source.stop(t + 0.25);
  }

  /**
   * Tiếng xào bài/lật sách nhanh (Gentle Shuffle)
   */
  public playShuffle() {
    if (this.isMuted || !this.ctx) return;
    this.resumeContext();

    let count = 0;
    const interval = setInterval(() => {
      this.playFlip();
      count++;
      if (count > 6) clearInterval(interval);
    }, 120);
  }

  /**
   * Tiếng hé lộ bài (Deep Reveal)
   * Thêm một chút âm trầm (body) để tạo cảm giác bìa sách dày
   */
  public playReveal() {
    if (this.isMuted || !this.ctx || !this.noiseBuffer) return;

    const t = this.ctx.currentTime;

    // 1. Thành phần "Sột soạt" chính
    const source = this.ctx.createBufferSource();
    source.buffer = this.noiseBuffer;
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(1800, t);
    filter.frequency.exponentialRampToValueAtTime(300, t + 0.3);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.2, t + 0.05);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.4);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);
    source.start(t);

    // 2. Thành phần "Cộp" nhẹ của bìa sách/bài dày (Subtle Thud)
    const thud = this.ctx.createOscillator();
    thud.type = 'sine';
    thud.frequency.setValueAtTime(100, t);
    thud.frequency.exponentialRampToValueAtTime(40, t + 0.1);

    const thudGain = this.ctx.createGain();
    thudGain.gain.setValueAtTime(0.08, t);
    thudGain.gain.exponentialRampToValueAtTime(0.001, t + 0.1);

    thud.connect(thudGain);
    thudGain.connect(this.ctx.destination);
    thud.start(t);
    thud.stop(t + 0.1);
  }

  /**
   * Tiếng chuông huyền bí trầm lắng (Soft Zen Chime)
   * Giảm cao độ và làm mềm âm sắc để không bị chói
   */
  public playChime() {
    if (this.isMuted || !this.ctx) return;

    const t = this.ctx.currentTime;
    const masterGain = this.ctx.createGain();
    masterGain.gain.setValueAtTime(0, t);
    masterGain.gain.linearRampToValueAtTime(0.08, t + 1.5); 
    masterGain.gain.exponentialRampToValueAtTime(0.001, t + 6.0); 

    // Hợp âm trầm ấm, bay bổng (không dùng nốt quá cao)
    const freqs = [196.00, 246.94, 293.66, 392.00, 493.88]; // G major 7 êm dịu

    freqs.forEach((f, i) => {
      if (!this.ctx) return;
      const osc = this.ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(f, t);

      const filter = this.ctx.createBiquadFilter();
      filter.type = 'lowpass';
      filter.frequency.setValueAtTime(1000, t); // Chặn các hài âm cao gây chói

      osc.connect(filter);
      filter.connect(masterGain);

      osc.start(t + (i * 0.15));
      osc.stop(t + 7.0);
    });

    masterGain.connect(this.ctx.destination);
  }
}

